// ─── BTS Biologie Médicale — première session 2027 ───
// Nouveau BTS rénové remplaçant progressivement le BTS ABM
import { FICHES_PC, QUIZ_THEMES_PC } from "./phys_chim.js";
const T={accent:"#4AEAAC",blue:"#5EB5FF",orange:"#FFB259",red:"#FF6370",pink:"#FF5DA0",text2:"#A199B2"};

// ─── BANQUES DE QUESTIONS ───

export const QB_BM_FONDAMENTAUX = [
  {id:"bm_f1",prompt:"L'accréditation ISO 15189 est la norme spécifique pour :",choices:["Les laboratoires industriels","Les laboratoires de biologie médicale (compétence technique + qualité)","Les hôpitaux en général","Les pharmacies"],answer:1,diff:1,explication:"ISO 15189 : norme internationale pour la compétence et la qualité des LBM. Accréditation par le COFRAC. Couvre toutes les phases : pré-analytique, analytique, post-analytique.",tags:["Qualité","ISO 15189","COFRAC","Accréditation"]},
  {id:"bm_f2",prompt:"Le DFG (Débit de Filtration Glomérulaire) chez un adulte sain est d'environ :",choices:["10-20 mL/min/1.73m²","90-120 mL/min/1.73m²","200-250 mL/min/1.73m²","5-10 mL/min/1.73m²"],answer:1,diff:1,explication:"DFG normal > 90 mL/min/1.73m². Estimé par formule CKD-EPI (créatinine ± cystatine C). Classification IRC : stades G1 (> 90) à G5 (< 15 = dialyse). < 60 = insuffisance rénale.",tags:["Biochimie","DFG","Rein","IRC"]},
  {id:"bm_f3",prompt:"Le bilan lipidique (EAL) comprend obligatoirement :",choices:["LDL-cholestérol uniquement","Cholestérol total, HDL-c, triglycérides, et LDL-c calculé par formule de Friedewald","Apolipoprotéines A et B uniquement","Uniquement les triglycérides"],answer:1,diff:1,explication:"EAL (Exploration d'une Anomalie Lipidique) : CT + HDL-c + TG → calcul LDL-c = CT - HDL-c - TG/5 (formule Friedewald, valide si TG < 4 g/L). LDL-c = risque cardiovasculaire principal.",tags:["Biochimie","Bilan lipidique","LDL","Cardiovasculaire"]},
  {id:"bm_f4",prompt:"L'hémoglobine A1c (HbA1c) de 7% correspond approximativement à une glycémie moyenne de :",choices:["5 mmol/L","8.5 mmol/L (≈ 1.5 g/L)","12 mmol/L","3 mmol/L"],answer:1,diff:2,explication:"Conversion HbA1c → glycémie estimée : GAM = 1.59 × HbA1c - 2.59 (en mmol/L). HbA1c 7% ≈ glycémie 8.5 mmol/L. Objectif diabétique : < 7% (53 mmol/mol IFCC).",tags:["Biochimie","HbA1c","Diabète","Glycémie"]},
  {id:"bm_f5",prompt:"La technique POCT (Point Of Care Testing) en biologie médicale désigne :",choices:["L'analyse en laboratoire centralisé","Les analyses délocalisées réalisées au plus près du patient (urgences, bloc, domicile)","Le contrôle qualité externe","L'accréditation des labos"],answer:1,diff:1,explication:"POCT : analyses biologiques hors laboratoire (au lit du patient, SMUR, urgences). Avantage : résultat rapide. Contrainte : qualité, formation des utilisateurs, traçabilité. Réglementé par l'arrêté POCT.",tags:["POCT","Biologie délocalisée","Organisation","Qualité"]},
  {id:"bm_f6",prompt:"La phase post-analytique en biologie médicale comprend :",choices:["La centrifugation des tubes","La validation biologique des résultats, le rendu et l'interprétation","Le prélèvement du patient","La calibration des automates"],answer:1,diff:1,explication:"Phase post-analytique : validation technique (CQI), validation biologique (biologiste médicale), édition du compte rendu, transmission sécurisée, archivage. Inclut la communication des résultats critiques.",tags:["Post-analytique","Validation","Compte rendu","Biologie médicale"]},
  {id:"bm_f7",prompt:"Le séquençage de nouvelle génération (NGS) en biologie médicale permet de :",choices:["Doser les hormones thyroïdiennes","Analyser simultanément des millions de fragments d'ADN (diagnostic génétique, oncologie, maladies rares)","Cultiver les bactéries plus rapidement","Mesurer la glycémie"],answer:1,diff:2,explication:"NGS (Next Generation Sequencing) : séquençage haut débit. Applications : maladies génétiques rares, oncologie (médecine de précision, mutations somatiques), pharmacogénomique, maladies infectieuses (métagénomique).",tags:["Biologie moléculaire","NGS","Génomique","Médecine de précision"]},
  {id:"bm_f8",prompt:"Le biologiste médical est le seul habilité à :",choices:["Prélever les tubes sanguins","Valider biologiquement les résultats et signer le compte rendu de biologie médicale","Utiliser les automates","Commander les réactifs"],answer:1,diff:1,explication:"Biologiste médical (médecin ou pharmacien biologiste) : validation biologique, rendu et interprétation des résultats, consultation (post-analytique). Responsabilité médicale du LBM.",tags:["Organisation","Biologiste médical","Validation","Réglementation"]},
  {id:"bm_f9",prompt:"La biologie moléculaire en routine microbiologique (PCR multiplex) permet de :",choices:["Cultiver les virus","Détecter simultanément plusieurs agents pathogènes en quelques heures","Réaliser un antibiogramme","Quantifier la CRP"],answer:1,diff:2,explication:"PCR multiplex : amplification simultanée de plusieurs cibles. Ex : panel respiratoire (grippe A/B, RSV, SARS-CoV-2, Legionella...) en 1-4h. Plus rapide que la culture, mais ne remplace pas tout.",tags:["Biologie moléculaire","PCR multiplex","Microbiologie","Diagnostic rapide"]},
  {id:"bm_f10",prompt:"La valeur critique (ou résultat d'alerte) en biologie médicale doit être :",choices:["Archivée sans action particulière","Communiquée sans délai au clinicien prescripteur (procédure documentée)","Ignorée si le patient est hospitalisé","Uniquement notée sur le compte rendu"],answer:1,diff:1,explication:"Résultats critiques (ex : K+ > 6.5, troponine très élevée, Hb < 6 g/dL) : communication immédiate (téléphone) au clinicien. Procédure documentée, traçabilité de l'appel. Exigence ISO 15189.",tags:["Post-analytique","Résultats critiques","Communication","ISO 15189"]},
  {id:"bm_f11",prompt:"La cytométrie en flux (flow cytometry) permet en hématologie de :",choices:["Uniquement compter les globules rouges","Identifier et quantifier des populations cellulaires par marqueurs de surface (immunophénotypage : lymphocytes CD4/CD8, blastes leucémiques)","Mesurer la viscosité sanguine","Détecter les parasites sanguins"],answer:1,diff:2,explication:"Cytométrie en flux : analyse multivariée de milliers de cellules/seconde par fluorescence. Immunophénotypage : CD4 (VIH), leucémies (blastes CD34+), lymphomes, GVH. Trieuse de cellules (cell sorting).",tags:["Hématologie","Cytométrie en flux","Immunophénotypage","CD4"]},
  {id:"bm_f12",prompt:"La spirochétose, la borréliose de Lyme et la syphilis partagent l'appartenance à l'ordre :",choices:["Mycobacteriales","Spirochaetales (spirochètes : organismes spiralés très flexibles)","Enterobacteriales","Campylobacterales"],answer:1,diff:3,explication:"Spirochètes : bactéries spiralées (Treponema pallidum/syphilis, Borrelia burgdorferi/Lyme, Leptospira). Mobilité par flagelles périplasmiques. Difficiles à cultiver, diagnostic sérologique.",tags:["Microbiologie","Spirochètes","Syphilis","Lyme"]},
];

export const QB_BM_HEMATOLOGIE_ADV = [
  {id:"bm_h1",prompt:"Le syndrome myéloprolifératif (SMP) se caractérise par :",choices:["Une aplasie médullaire","Une prolifération clonale d'une ou plusieurs lignées myéloïdes (hyperleucocytose, polyglobulie, thrombocytose)","Une pancytopénie","Une leucémie aiguë uniquement"],answer:1,diff:2,explication:"SMP : prolifération clonale cellules souches myéloïdes. LMC (JAK2), Polyglobulie de Vaquez (JAK2 V617F), TE (thrombocy. essentielle), myélofibrose. Anomalies moléculaires spécifiques.",tags:["Hématologie","SMP","LMC","JAK2"]},
  {id:"bm_h2",prompt:"La mutation JAK2 V617F est détectée dans :",choices:["La leucémie myéloïde chronique uniquement","La polyglobulie de Vaquez (95%), la thrombocytémie essentielle (50%), la myélofibrose (50%)","Les leucémies aiguës lymphoblastiques","Le myélome multiple"],answer:1,diff:3,explication:"JAK2 V617F : mutation gain de fonction de la kinase JAK2. Pathognomonique des SMP non-LMC. PCR quantitative sur sang total. LMC : translocation t(9;22) = chromosome Philadelphie = BCR-ABL.",tags:["Hématologie","JAK2","SMP","Biologie moléculaire"]},
  {id:"bm_h3",prompt:"Le myélome multiple (MM) produit en excès :",choices:["Des globules rouges","Une immunoglobuline monoclonale (pic M à l'EPP) par des plasmocytes clonaux","Des plaquettes","Des lymphocytes T"],answer:1,diff:2,explication:"Myélome : prolifération plasmocytaire clonale → Ig monoclonale (IgG 60%, IgA 20%, chaînes légères). Diagnostic : EPP (pic M) + immunofixation + dosage chaînes légères libres. Complications : ostéolyse, IRC.",tags:["Hématologie","Myélome","Immunofixation","Plasmocytes"]},
  {id:"bm_h4",prompt:"L'examen de moelle osseuse (myélogramme) est réalisé par ponction :",choices:["Fémorale","Sternale ou iliaque postérieure (crête iliaque)","Vertébrale","Trachéale"],answer:1,diff:1,explication:"Myélogramme : ponction sternale (ou crête iliaque postérieure chez enfant). Aspiration moelle → frottis MGG → formule médullaire. Diagnostic leucémies, aplasies, métastases médullaires.",tags:["Hématologie","Myélogramme","Moelle osseuse","Diagnostic"]},
  {id:"bm_h5",prompt:"La biopsie ostéo-médullaire (BOM) est préférée au myélogramme quand :",choices:["La moelle est hypercellulaire","La moelle est sèche (aplasie, myélofibrose) ou pour évaluer l'architecture","Le patient est sous AVK","La NFS est normale"],answer:1,diff:2,explication:"BOM : prélèvement de carottes de moelle + travécules osseuses (trépan). Architecture conservée. Indiquée : myélofibrose (moelle fibreuse), aplasie médullaire, lymphome avec atteinte médullaire, myélogramme blanc.",tags:["Hématologie","BOM","Aplasie","Myélofibrose"]},
  {id:"bm_h6",prompt:"Les schizocytes (fragments de GR) sur frottis orientent vers :",choices:["Carence en fer","Microangiopathie thrombotique (MAT) : SHU, PTT, CIVD","Hémolyse auto-immune","Thalassémie"],answer:1,diff:2,explication:"Schizocytes = GR fragmentés par agressions mécaniques sur fibrine ou prothèse. MAT = SHU (STEC ou atypique), PTT (déficit ADAMTS13), CIVD. Diagnostic urgent : plasmaphérèse si PTT.",tags:["Hématologie","Schizocytes","MAT","Frottis"]},
  {id:"bm_h7",prompt:"Le test d'Élution (test de Kleihauer) est utilisé pour :",choices:["Mesurer le fibrinogène","Quantifier les hématies fœtales dans le sang maternel (hémorragie fœto-maternelle)","Dépister la drépanocytose","Mesurer le taux de réticulocytes"],answer:1,diff:3,explication:"Test de Kleihauer : élution de l'Hb A adulte (HbA sensible à pH acide) → GR fœtaux (HbF résistante) colorés en rose, GR maternels fantômes. Permet de calculer la dose de Rhophylac à injecter.",tags:["Hématologie","Kleihauer","Hémorragie fœto-maternelle","Rhésus"]},
  {id:"bm_h8",prompt:"Le temps de thrombine (TT) mesure :",choices:["La voie extrinsèque","La conversion du fibrinogène en fibrine par la thrombine exogène ajoutée","La voie intrinsèque","La fibrinolyse"],answer:1,diff:3,explication:"TT = temps nécessaire pour coaguler après ajout de thrombine exogène. Allongé si : fibrinogène bas, fibrinogène anormal (dysfibrinogénémie), héparinémie résiduelle, produits de dégradation fibrine.",tags:["Hématologie","Temps de thrombine","Hémostase","Fibrinogène"]},
];

export const QB_BM_BIOCHIMIE_SPEC = [
  {id:"bm_bc1",prompt:"Le NT-proBNP est un marqueur de :",choices:["L'infarctus du myocarde","L'insuffisance cardiaque (sécrétion par les myocytes lors de la distension ventriculaire)","L'embolie pulmonaire","L'hypertension artérielle chronique"],answer:1,diff:2,explication:"BNP/NT-proBNP : peptides natriurétiques sécrétés par les myocytes ventriculaires lors d'une surcharge de pression ou de volume. NT-proBNP > 125 pg/mL (ambulatoire) = seuil d'alerte. Excellent VPN pour exclure IC.",tags:["Biochimie spécialisée","NT-proBNP","Insuffisance cardiaque","Marqueurs"]},
  {id:"bm_bc2",prompt:"La formule de Friedewald pour calculer le LDL-cholestérol est :",choices:["LDL = CT + HDL + TG/5","LDL = CT - HDL - TG/5 (valide uniquement si TG < 4 g/L)","LDL = CT × HDL × TG","LDL = TG/2 - HDL"],answer:1,diff:2,explication:"Friedewald : LDL-c = CT - HDL-c - TG/5 (en g/L). Invalide si TG > 4 g/L (hypertriglycéridémie) → dosage LDL direct. LDL-c idéal < 0.70 g/L chez patients à risque cardiovasculaire très élevé.",tags:["Biochimie spécialisée","LDL","Friedewald","Lipidologie"]},
  {id:"bm_bc3",prompt:"La Lp(a) (lipoprotéine a) est un facteur de risque cardiovasculaire :",choices:["Modifiable facilement par le régime","Génétiquement déterminé, peu modifiable par le mode de vie, dosage ponctuel suffisant","Inexistant selon les nouvelles recommandations","Uniquement marqueur d'inflammation"],answer:1,diff:3,explication:"Lp(a) : LDL + apolipoprotéine(a). Athérogène ET prothrombotique. Niveau génétiquement déterminé (peu modifié par statines). Dosage : 1 fois dans la vie. > 50 mg/dL = risque cardiovasculaire accru.",tags:["Biochimie spécialisée","Lp(a)","Cardiovasculaire","Lipidologie"]},
  {id:"bm_bc4",prompt:"Le dosage de la cystatine C est préféré à la créatinine pour évaluer le DFG :",choices:["Chez les patients avec une masse musculaire normale","En cas de sarcopénie, obésité, ou quand la créatinine est peu fiable (muscle anormal)","Chez les sportifs uniquement","Il ne mesure pas le DFG"],answer:1,diff:2,explication:"Cystatine C : produite par toutes les cellules nucléées (indépendante de la masse musculaire). Meilleur marqueur DFG en cas de sarcopénie (sujet âgé, dénutri), obésité, cirrhose. Formule CKD-EPI avec cystatine C.",tags:["Biochimie spécialisée","Cystatine C","DFG","Rein"]},
  {id:"bm_bc5",prompt:"Le syndrome métabolique associe :",choices:["Hypertension + anémie + diabète","Obésité abdominale + dyslipidémie (TG élevés, HDL bas) + HTA + hyperglycémie (au moins 3/5 critères)","Uniquement l'obésité et le diabète","Insuffisance rénale + hypertension"],answer:1,diff:2,explication:"Syndrome métabolique (IDF/AHA) : tour de taille > 94 cm H / 80 cm F + TG > 1.7 mmol/L + HDL bas + TA > 130/85 + glycémie > 5.6 mmol/L (3/5 critères). Risque cardiovasculaire et diabète type 2.",tags:["Biochimie spécialisée","Syndrome métabolique","Cardiovasculaire","Dyslipidémie"]},
  {id:"bm_bc6",prompt:"Les marqueurs de l'inflammation aiguë (réactants de phase aiguë positive) comprennent :",choices:["L'albumine et la préalbumine (diminuent en phase aiguë)","CRP, fibrinogène, ferritine, haptoglobine, alpha1-antitrypsine (augmentent en phase aiguë)","Uniquement la CRP","Le cholestérol et les triglycérides"],answer:1,diff:2,explication:"Réactants de phase aiguë + : CRP (précoce), fibrinogène, ferritine, haptoglobine, alpha-1 antitrypsine, protéine amyloïde sérique A. Réactants - : albumine, préalbumine (transfert), RBP (diminuent car foie détourne les ressources).",tags:["Biochimie spécialisée","Inflammation","Réactants phase aiguë","CRP"]},
  {id:"bm_bc7",prompt:"Le dosage de la 25-OH-vitamine D reflète :",choices:["L'activité de la vitamine D","Le statut en vitamine D de l'organisme (forme de stockage circulante)","La forme active de la vitamine D","L'absorption intestinale du calcium"],answer:1,diff:2,explication:"25-OH-vitamine D = forme circulante, de stockage (demi-vie 2-3 sem). < 50 nmol/L = insuffisance. < 30 nmol/L = carence. Forme active : 1,25-(OH)₂D (calcitriol, demi-vie quelques heures). Dosé par immunodosage ou LC-MS/MS.",tags:["Biochimie spécialisée","Vitamine D","Calcémie","Métabolisme osseux"]},
  {id:"bm_bc8",prompt:"La PTH (parathormone) est abaissée en cas de :",choices:["Hyperparathyroïdie primaire","Hypercalcémie d'autre cause (sarcoïdose, myélome, métastases osseuses — PTH freinée par rétrocontrôle négatif)","Insuffisance rénale chronique","Carence en vitamine D"],answer:1,diff:3,explication:"PTH régule calcémie : hypocalcémie → ↑PTH. Hypercalcémie non PTH-dépendante (myélome, métastases, granulomatose) → ↓PTH (rétrocontrôle). Hyperparathyroïdie primaire : PTH inappropriément élevée malgré hypercalcémie.",tags:["Biochimie spécialisée","PTH","Calcium","Parathyroïde"]},
  {id:"bm_bc9",prompt:"L'albumine est le marqueur de dénutrition protéique mais est peu sensible car :",choices:["Elle est produite par le rein","Sa longue demi-vie (21 jours) la rend peu réactive aux variations nutritionnelles récentes — utiliser plutôt préalbumine (transthyrétine)","Elle n'est pas dosable en routine","Elle est trop chère à doser"],answer:1,diff:2,explication:"Albumine : demi-vie 21 jours → marker de dénutrition chronique. Préalbumine (transthyrétine) : demi-vie 2-3 jours → marker de dénutrition aiguë ou de la réponse nutritionnelle. CRP doit être < 10 pour interpréter les protéines nutritionnelles.",tags:["Biochimie spécialisée","Albumine","Dénutrition","Préalbumine"]},
  {id:"bm_bc10",prompt:"Le dosage de la TSH (thyréostimuline) est suffisant en première intention car :",choices:["C'est le marqueur le moins cher","La TSH est le meilleur reflet de l'activité thyroïdienne périphérique (axe hypothalamo-hypophyso-thyroïdien)","Elle est toujours normale en cas de maladie thyroïdienne","La T4 libre est moins spécifique"],answer:1,diff:1,explication:"TSH : très sensible (amplification axiale). Toute anomalie thyroïdienne primaire se traduit par ↑ ou ↓TSH. Si TSH anormale → doser T4L (hypothyroïdie : TSH↑+T4L↓ ; hyperthyroïdie : TSH↓+T4L↑). TSH normale = euthyroïdie dans > 99% des cas.",tags:["Biochimie spécialisée","TSH","Thyroïde","Axe HPT"]},
  {id:"bm_bc11",prompt:"L'alpha-fœtoprotéine (AFP) est élevée en cas de :",choices:["Cancer de la prostate","Carcinome hépatocellulaire (CHC) et tumeurs germinales (testicule, ovaire)","Leucémie aiguë","Infarctus du myocarde"],answer:1,diff:1,explication:"AFP : oncoprotéine fœtale. Élevée (> 400 ng/mL) : CHC sur cirrhose (sensibilité 60%, spécificité élevée). Aussi : tumeurs germinales non séminomateuses (TGNS). Surveillance CHC : AFP + échographie tous les 6 mois chez cirrhotiques.",tags:["Biochimie spécialisée","AFP","CHC","Marqueurs tumoraux"]},
  {id:"bm_bc12",prompt:"Le CA 125 est le marqueur de surveillance du :",choices:["Cancer du sein","Cancer de l'ovaire (épithélial séreux)","Cancer colorectal","Cancer du pancréas"],answer:1,diff:1,explication:"CA 125 : glycoprotéine associée aux cellules mésothéliales et épithéliales ovariennes. > 35 U/mL = significatif (sans seuil diagnostique formel). Utilisé en surveillance post-traitement cancer de l'ovaire (rechute). Peut être élevé en endométriose.",tags:["Biochimie spécialisée","CA 125","Ovaire","Marqueurs tumoraux"]},
  {id:"bm_bc13",prompt:"La technique ELISA (Enzyme Linked ImmunoSorbent Assay) est basée sur :",choices:["L'électrophorèse des protéines","La liaison Ag-Ac avec révélation enzymatique (substrate colorimétrique → absorbance proportionnelle à la concentration)","La précipitation par immunodiffusion","La chromatographie"],answer:1,diff:1,explication:"ELISA : plaque 96 puits. Capture Ac ou Ag sur phase solide → ajout échantillon → Ac de détection conjugué enzyme → substrat → couleur proportionnelle à la concentration. Sandwich ELISA (sandwiche l'Ag entre 2 Ac) = le plus précis.",tags:["Immunologie","ELISA","Technique","Immunodosage"]},
  {id:"bm_bc14",prompt:"La technique d'immunofluorescence indirecte (IFI) sur cellules HEp-2 est utilisée pour :",choices:["Doser la CRP","Dépister les anticorps anti-nucléaires (AAN) — aspect de la fluorescence oriente le type d'auto-Ac","Diagnostiquer le paludisme","Mesurer l'HbA1c"],answer:1,diff:2,explication:"IFI HEp-2 : cellules de carcinome laryngé humain (riches en Ag nucléaires). Sérum patient dilué + Ac anti-IgG humaines fluorescents. Aspect : moucheté (anti-SSA/SSB), homogène (anti-ADN), centromérique (CREST), nucléolaire (anti-SCL70).",tags:["Immunologie","IFI","AAN","Auto-immunité"]},
  {id:"bm_bc15",prompt:"La technique LC-MS/MS (chromatographie liquide couplée à la spectrométrie de masse en tandem) est la méthode de référence pour :",choices:["La NFS","Le dosage des stéroïdes, vitamines, médicaments (haute spécificité, haute sensibilité, pas d'interférence)","L'antibiogramme","L'électrophorèse des protéines"],answer:1,diff:3,explication:"LC-MS/MS : gold standard pour stéroïdes (testostérone, cortisol), vitamines (25-OH-D), immunosuppresseurs, drogues. Évite les interférences immunologiques des immunodosages (anticorps hétérophiles). Traçabilité vers étalons JCTLM.",tags:["Biochimie spécialisée","LC-MS/MS","Spectrométrie de masse","Méthodes de référence"]},
];

export const QB_BM_REIN_HYDRO = [
  {id:"bm_rh1",prompt:"Le néphron est l'unité fonctionnelle du rein. Ses principales composantes sont :",choices:["Uniquement le glomérule","Glomérule (capsule de Bowman) + tubule proximal + anse de Henle + tubule distal + tube collecteur","Glomérule + cortex seulement","Médulla + bassinet"],answer:1,diff:1,explication:"Le néphron comprend : corpuscule rénal (glomérule entouré de la capsule de Bowman) + système tubulaire (tubule contourné proximal, anse de Henle dans la médulla, tubule contourné distal, tube collecteur). Le rein contient ~1 million de néphrons.",tags:["Rein","Néphron","Anatomie","Physiologie"]},
  {id:"bm_rh2",prompt:"L'eau corporelle totale représente chez un adulte sain :",choices:["20-30% du poids corporel","60-70% du poids corporel (environ 42L pour 70 kg)","80-90% du poids corporel","10-15% du poids corporel"],answer:1,diff:1,explication:"Eau corporelle totale (ACT) ≈ 60% du poids (homme) à 55% (femme, + masse grasse). Répartition : compartiment intracellulaire (LIC) = 2/3 de l'ACT (≈ 28L) ; compartiment extracellulaire (LEC) = 1/3 (≈ 14L : plasma 3L + interstitiel 11L).",tags:["Hydroélectrolytique","Eau","Compartiments","Physiologie"]},
  {id:"bm_rh3",prompt:"Le sodium (Na⁺) est principalement localisé dans :",choices:["Le milieu intracellulaire","Le milieu extracellulaire (plasma et liquide interstitiel, 135-145 mmol/L)","Les érythrocytes","Les os"],answer:1,diff:1,explication:"Na⁺ : cation principal du secteur extracellulaire. Natrémie normale : 135-145 mmol/L. Détermine l'osmolalité extracellulaire. En intracellulaire, Na⁺ est faible (10-15 mmol/L), K⁺ est élevé (150 mmol/L). Pompe Na⁺/K⁺-ATPase maintient cet équilibre.",tags:["Hydroélectrolytique","Sodium","Natrémie","Compartiments"]},
  {id:"bm_rh4",prompt:"L'osmolalité plasmatique se calcule approximativement par la formule :",choices:["2 × Natrémie","2 × Natrémie + Glycémie + Urée (toutes en mmol/L) ≈ 280-295 mOsm/kg","Na + K + Cl","Glycémie × 2"],answer:1,diff:2,explication:"Osmolalité (mOsm/kg) = 2 × Na⁺ + glycémie + urée (tout en mmol/L). Normale : 280-295 mOsm/kg. Hyperosmolalité : DI, hyperglycémie, hypernatrémie. Hypo-osmolalité : hyponatrémie, SIADH.",tags:["Hydroélectrolytique","Osmolalité","Sodium","Calcul"]},
  {id:"bm_rh5",prompt:"L'hyponatrémie (Na⁺ < 135 mmol/L) est dite hypo-osmolaire vraie lorsqu'elle est associée à :",choices:["Une hyperglycémie","Une SIADH (syndrome d'antidiurèse inappropriée), une hémodilution, une perte de sel","Une élévation des lipides","Une hyperprotidémie"],answer:1,diff:2,explication:"Hyponatrémie hypo-osmolaire vraie : SIADH (sécrétion inappropriée d'ADH → rétention d'eau), ICC, cirrhose (dilution). Hyponatrémie iso-osmolaire : hyperprotidémie, hyperlipidémie (pseudohyponatrémie). Hyponatrémie hyperosmolaire : hyperglycémie (attraction osmotique).",tags:["Hydroélectrolytique","Hyponatrémie","SIADH","Osmolalité"]},
  {id:"bm_rh6",prompt:"Le potassium (K⁺) plasmatique normal est :",choices:["6-8 mmol/L","3.5-5 mmol/L (kaliémie normale)","1-2 mmol/L","8-10 mmol/L"],answer:1,diff:1,explication:"Kaliémie normale : 3.5-5.0 mmol/L. Hypokaliémie (< 3.5) : risque arythmie, paralysie. Hyperkaliémie (> 5.5) : urgence cardiologique (> 6.5 : risque FV). K⁺ intracellulaire ≈ 150 mmol/L (maintenu par la pompe Na⁺/K⁺-ATPase).",tags:["Hydroélectrolytique","Potassium","Kaliémie","Biochimie"]},
  {id:"bm_rh7",prompt:"L'aldostérone (système rénine-angiotensine-aldostérone, SRAA) agit principalement en :",choices:["Inhibant la réabsorption du sodium","Stimulant la réabsorption du Na⁺ et l'excrétion du K⁺ dans le tube collecteur rénal","Augmentant la filtration glomérulaire","Inhibant l'ADH"],answer:1,diff:2,explication:"Aldostérone (cortex surrénalien, zona glomerulosa) : se fixe sur récepteurs minéralocorticoïdes → ↑ canaux ENaC (Na⁺) et pompe Na⁺/K⁺-ATPase → réabsorption Na⁺ + eau, excrétion K⁺ et H⁺. Activée par angiotensine II et hyperkaliémie.",tags:["Rein","SRAA","Aldostérone","Régulation"]},
  {id:"bm_rh8",prompt:"L'ADH (hormone antidiurétique / vasopressine) est libérée par :",choices:["Le cortex surrénalien","La neurohypophyse (post-hypophyse), en réponse à une hyperosmolalité ou à une hypovolémie","Le rein directement","La thyroïde"],answer:1,diff:2,explication:"ADH (arginine vasopressine) : synthétisée dans l'hypothalamus, stockée et libérée par la neurohypophyse. Stimuli : ↑ osmolalité (principal), ↓ volémie. Cible : canaux aquaporine 2 (AQP2) du tube collecteur → réabsorption d'eau → concentration des urines.",tags:["Rein","ADH","Vasopressine","Régulation"]},
  {id:"bm_rh9",prompt:"La protéinurie pathologique chez l'adulte est définie par :",choices:["Plus de 10 mg/j","Plus de 300 mg/j (normale < 150 mg/j) — la micro-albuminurie = 30-300 mg/j","Plus de 10 g/j uniquement","L'absence de protéines dans les urines"],answer:1,diff:2,explication:"Protéinurie normale < 150 mg/j (dont albumine < 30 mg/j). Micro-albuminurie = 30-300 mg/j (marqueur précoce de néphropathie diabétique ou cardiovasculaire). Macroprotéinurie > 300 mg/j (ou > 500 mg/j selon certaines définitions). Syndrome néphrotique > 3 g/j.",tags:["Rein","Protéinurie","Albuminurie","Néphropathie"]},
  {id:"bm_rh10",prompt:"La créatinine sérique est un marqueur de la fonction rénale car :",choices:["Elle est synthétisée par le rein","Elle est filtrée librement par le glomérule et peu réabsorbée, sa concentration reflète donc le DFG","Elle est réabsorbée en totalité","Elle est sécrétée par les hépatocytes"],answer:1,diff:1,explication:"Créatinine : produit du métabolisme musculaire (créatine-phosphate). Filtration glomérulaire + légère sécrétion tubulaire. Indépendante de l'alimentation (contrairement à l'urée). Sa clairance estime le DFG. Formule CKD-EPI intègre : créatinine, âge, sexe. Limites : varie avec la masse musculaire.",tags:["Rein","Créatinine","DFG","Biochimie"]},
  {id:"bm_rh11",prompt:"L'ECBU (examen cytobactériologique des urines) est positif pour une infection urinaire si :",choices:["Leucocyturie > 1000/mL uniquement","Leucocyturie ≥ 10⁴/mL + bactériurie ≥ 10³ UFC/mL (pour certains germes) à 10⁵ UFC/mL (germes courants)","Toute bactérie dans les urines","Uniquement si hémoculture positive"],answer:1,diff:2,explication:"ECBU positif : leucocyturie ≥ 10⁴/mL + bactériurie ≥ 10³ (E. coli + S. saprophyticus), 10⁴ ou 10⁵ UFC/mL selon le germe et le contexte (recommandations SPILF 2021). Germes les plus fréquents : E. coli (75-80%), Klebsiella, Staphylococcus saprophyticus (femme jeune).",tags:["Rein","ECBU","Infection urinaire","Microbiologie"]},
  {id:"bm_rh12",prompt:"L'insuffisance rénale chronique (IRC) stade G4 correspond à un DFG de :",choices:["60-89 mL/min/1.73m²","15-29 mL/min/1.73m² (stade pré-dialyse, néphroprotection active)","< 15 mL/min/1.73m² (dialyse)","90-120 mL/min/1.73m²"],answer:1,diff:2,explication:"Classification CKD (KDIGO) : G1 > 90 (marqueurs rénaux), G2 60-89, G3a 45-59, G3b 30-44, G4 15-29 (préparation dialyse/greffe), G5 < 15 (dialyse ou transplantation). Étiologies principales : diabète, HTA, glomérulonéphrites.",tags:["Rein","IRC","DFG","Classification CKD"]},
];

export const QB_BM_HEMOSTASE = [
  {id:"bm_hm1",prompt:"L'hémostase primaire aboutit à la formation de :",choices:["La fibrine insoluble","Le clou plaquettaire (thrombus blanc)","La prothrombine activée","Le plasminogène"],answer:1,diff:1,explication:"L'hémostase primaire est la 1ère réponse à une lésion vasculaire : vasoconstriction → adhésion plaquettaire (vWF + GPIb → collagène) → activation plaquettaire (ADP, TXA2) → agrégation (fibrinogène + GPIIb/IIIa) → clou plaquettaire = thrombus blanc. La fibrine insoluble est formée lors de la coagulation (phase secondaire).",tags:["Hémostase","Plaquettes","vWF","Clou plaquettaire"]},
  {id:"bm_hm2",prompt:"Le TP (Temps de Quick) explore préférentiellement :",choices:["La voie intrinsèque (XI, IX, VIII)","La voie extrinsèque et commune (VII, X, V, II, I)","Les plaquettes","La fibrinolyse"],answer:1,diff:1,explication:"Le TP teste la voie extrinsèque (facteur VII + facteur tissulaire) et la voie commune (Xa → thrombine → fibrine), soit les facteurs VII, X, V, II (prothrombine) et I (fibrinogène). Il est exprimé en % (normal > 70%) ou en INR. Allongé sous AVK et en insuffisance hépatocellulaire.",tags:["TP","Coagulation","Voie extrinsèque","AVK"]},
  {id:"bm_hm3",prompt:"L'INR (International Normalized Ratio) est utilisé principalement pour surveiller :",choices:["Le traitement par héparine","Le traitement par anti-vitamines K (AVK)","Le traitement par HBPM","La thrombopénie immune"],answer:1,diff:1,explication:"INR = (TP patient / TP témoin)^ISI. Standardise le TP entre laboratoires. Cible thérapeutique : 2-3 pour FA, MTEV, valvulopathie ; 2.5-3.5 pour valve mécanique mitrale. INR > 5 = risque hémorragique majeur → adaptation de dose ou antidote (vitamine K).",tags:["INR","AVK","Anticoagulants","Surveillance biologique"]},
  {id:"bm_hm4",prompt:"Le TCA (Temps de Céphaline Activée) est allongé en cas d'hémophilie A car :",choices:["Le facteur XII est déficient","Le facteur VIII est déficient (voie intrinsèque)","Le facteur VII est déficient","La fibrine ne se forme pas"],answer:1,diff:2,explication:"L'hémophilie A = déficit en facteur VIII (liée à l'X, touche surtout les hommes). Le TCA explore la voie intrinsèque (XII, XI, IX, VIII) + commune (X, V, II, I). Un déficit en facteur VIII allonge le TCA sans modifier le TP. Hémophilie B = déficit facteur IX (même phénotype clinique).",tags:["TCA","Hémophilie A","Facteur VIII","Voie intrinsèque"]},
  {id:"bm_hm5",prompt:"Les D-dimères sont des marqueurs biologiques de :",choices:["L'activation plaquettaire","La dégradation de la fibrine réticulée par la plasmine","L'insuffisance hépatique","L'activation du complément"],answer:1,diff:1,explication:"Les D-dimères = fragments de fibrine croisée (réticulée par le facteur XIIIa) dégradée par la plasmine (fibrinolyse). Valeur normale < 500 µg/L. Excellente VPN pour exclure TVP/EP si < 500 µg/L. Positifs aussi dans : grossesse, cancer, post-opératoire, inflammation (peu spécifiques).",tags:["D-dimères","Fibrinolyse","TVP","Embolie pulmonaire"]},
  {id:"bm_hm6",prompt:"Dans la CIVD (Coagulation Intravasculaire Disséminée), on retrouve typiquement :",choices:["TP normal, TCA court, fibrinogène élevé","TP allongé, TCA allongé, fibrinogène effondré, D-dimères très élevés","TP normal, plaquettes normales, fibrinogène élevé","TCA allongé isolé, autres paramètres normaux"],answer:1,diff:2,explication:"La CIVD = activation massive de la coagulation → consommation de tous les facteurs et plaquettes. Bilan caractéristique : TP ↓ (<50%), TCA allongé (>1.5× témoin), fibrinogène < 1 g/L, D-dimères > 2000 µg/L, thrombopénie < 100 G/L. Causes : sepsis sévère, leucémie aiguë, crush syndrome, choc hémorragique.",tags:["CIVD","Coagulation","Bilan","Urgence biologique"]},
  {id:"bm_hm7",prompt:"Le facteur V Leiden est associé à une résistance à :",choices:["La vitamine K","La protéine C activée (PCa), entraînant un risque thrombotique accru","L'héparine","La fibrinolyse"],answer:1,diff:2,explication:"Mutation R506Q du gène du facteur V → facteur V non clivé par la protéine C activée → facteur V actif persiste → hypercoagulabilité. Risque thrombose × 5-8 (hétérozygote) à × 80 (homozygote). C'est la thrombophilie héréditaire la plus fréquente en Europe caucasienne (~5%). Dépistage par biologie moléculaire (PCR).",tags:["Facteur V Leiden","Thrombophilie","Protéine C","Thrombose"]},
  {id:"bm_hm8",prompt:"Les AVK (anti-vitamines K) inhibent la synthèse des facteurs :",choices:["I, II, III, IV","II, VII, IX, X (et protéines C et S)","VIII, XI, XII et vWF","Xa et IIa uniquement"],answer:1,diff:2,explication:"Les AVK (warfarine, fluindione, acénocoumarol) inhibent la carboxylase qui active les facteurs vitamine K-dépendants : II (prothrombine), VII, IX, X, protéine C, protéine S, protéine Z. Délai d'action 2-4 jours (demi-vie facteur VII = 6h). Antidote : vitamine K IV ± PPSB (concentré de complexe prothrombinique) si urgence.",tags:["AVK","Vitamine K","Anticoagulants","Facteurs dépendants"]},
  {id:"bm_hm9",prompt:"Les HBPM (héparines bas poids moléculaire) agissent principalement en inhibant :",choices:["Le facteur VII","Le facteur Xa (et moins la thrombine IIa que l'HNF)","Le fibrinogène","Les plaquettes"],answer:1,diff:2,explication:"HBPM (enoxaparine = Lovenox, daltéparine, tinzaparine) : rapport anti-Xa/anti-IIa ≈ 2-4 (vs HNF = 1). Inhibent le Xa en se fixant sur l'antithrombine III (ATI). Avantages vs HNF : biodisponibilité SC > 90%, demi-vie plus longue, moins de TIH. Surveillance anti-Xa si obésité, grossesse ou IRC.",tags:["HBPM","Facteur Xa","Anticoagulants","Anti-Xa"]},
  {id:"bm_hm10",prompt:"Le taux normal de fibrinogène plasmatique est de :",choices:["0.5-1 g/L","2-4 g/L","7-10 g/L","0.1-0.3 g/L"],answer:1,diff:1,explication:"Fibrinogène (facteur I) : 2-4 g/L. Abaissé en : CIVD (consommation), insuffisance hépatique sévère (défaut de synthèse), hyperfibrinolyse, fibrinogénémie congénitale. Élevé en : inflammation aiguë (protéine de phase aiguë), grossesse. Un fibrinogène > 5 g/L peut masquer une CIVD débutante.",tags:["Fibrinogène","Coagulation","Valeurs normales","CIVD"]},
  {id:"bm_hm11",prompt:"Parmi les anticoagulants oraux directs (AOD), les inhibiteurs directs du facteur Xa sont :",choices:["Dabigatran (Pradaxa)","Rivaroxaban (Xarelto), apixaban (Eliquis), edoxaban","Fondaparinux (Arixtra)","Bivalirudine (Angiox)"],answer:1,diff:2,explication:"AOD anti-Xa : rivaroxaban, apixaban, edoxaban (suffixe -xaban). Dabigatran = inhibiteur direct de la thrombine (IIa). Fondaparinux = pentasaccharide anti-Xa indirect (via ATIII) ≠ AOD. Pas de surveillance biologique systématique (sauf situations particulières : mesure anti-Xa spécifique ou TP pour rivaroxaban).",tags:["AOD","Anti-Xa","Rivaroxaban","Apixaban","Anticoagulants"]},
  {id:"bm_hm12",prompt:"La thrombopénie induite par l'héparine de type 2 (TIH 2) est dangereuse car :",choices:["Elle entraîne un risque hémorragique uniquement","Elle provoque paradoxalement des thromboses veineuses et artérielles graves","Elle est due à une destruction médullaire des précurseurs","Elle n'est associée qu'à l'héparine non fractionnée standard"],answer:1,diff:3,explication:"TIH 2 = formation d'anticorps anti-PF4/héparine (IgG) → activation plaquettaire massive → thrombocytopénie + thromboses paradoxales (pontage coronaire, AVC, embolie). Survient J5-J10 sous héparine (toutes formes). Diagnostic : score 4T + dosage Ac anti-PF4/H. Traitement : arrêt héparine + anticoagulant alternatif (fondaparinux, argatroban).",tags:["TIH","Héparine","Thrombopénie","Thrombose paradoxale"]},
];

export const QB_BM_IMMUNOPATH = [
  {id:"bm_ip1",prompt:"Les anticorps anti-nucléaires (AAN/FAN) sont recherchés par :",choices:["ELISA sur plaque 96 puits uniquement","Immunofluorescence indirecte (IFI) sur cellules HEp-2, en dépistage","PCR en temps réel","Western blot anti-ADN"],answer:1,diff:1,explication:"Les AAN sont dépistés par IFI sur cellules HEp-2 (larges, nucléolées). Les patterns de fluorescence orientent : homogène → anti-ADN natif (LES) ; moucheté → anti-ENA (anti-Sm, anti-Ro/SSA, anti-La/SSB, anti-Scl70, anti-Jo1) ; nucléolaire → anti-PM/Scl (myosite-sclérodermie). Seuil significatif : ≥ 1/160 ou ≥ 1/320.",tags:["AAN","IFI","HEp-2","Auto-anticorps"]},
  {id:"bm_ip2",prompt:"Les anti-ADN natif (double brin, dsDNA) sont spécifiques de :",choices:["La polyarthrite rhumatoïde","Le lupus érythémateux systémique (LES)","La sclérodermie systémique","La maladie de Sjögren"],answer:1,diff:1,explication:"Anti-ADNn (double brin) = marqueur diagnostique ET de suivi du LES. Spécificité > 97%. Leur taux corrèle avec l'activité de la maladie (notamment la néphrite lupique). Méthodes de détection : ELISA, Farr (radio-immunodosage), IFI sur Crithidia luciliae (flagellé). Un titre élevé + hypocomplémentémie C3/C4 = poussée imminente.",tags:["Anti-ADN","Lupus","LES","Spécificité"]},
  {id:"bm_ip3",prompt:"Le facteur rhumatoïde (FR) est :",choices:["Un anticorps anti-CCP (peptide citrulliné)","Une IgM (principalement) dirigée contre la portion Fc des IgG","Un marqueur très spécifique de la polyarthrite rhumatoïde","Un complément activé"],answer:1,diff:2,explication:"Le FR = auto-anticorps (IgM, mais aussi IgG, IgA) dirigé contre la portion Fc des IgG. Sensibilité PR : 70-80%, mais spécificité modérée (~80%) car positif aussi dans : infections chroniques, hépatites, cryoglobulinémie, syndromes de Sjögren, sujets âgés. Anti-CCP (anti-peptides citrullinés) est bien plus spécifique de la PR (> 95%).",tags:["Facteur rhumatoïde","PR","Auto-anticorps","Spécificité"]},
  {id:"bm_ip4",prompt:"La thyroïdite de Hashimoto est caractérisée biologiquement par :",choices:["Anticorps anti-récepteur TSH stimulants + TSH basse","Anti-TPO élevés (anti-thyroid peroxydase) + TSH élevée (hypothyroïdie)","Anti-Scl70 positifs","Hypocomplémentémie C3+C4"],answer:1,diff:1,explication:"Thyroïdite de Hashimoto = maladie auto-immune thyroïdienne. Auto-anticorps : anti-TPO (95% des cas, titre élevé) + anti-thyroglobuline (moins spécifiques). La destruction progressive de la glande → hypothyroïdie (TSH ↑, T4L ↓). C'est la cause la plus fréquente d'hypothyroïdie en France et la plus fréquente maladie auto-immune chez la femme.",tags:["Hashimoto","Thyroïde","Anti-TPO","Hypothyroïdie"]},
  {id:"bm_ip5",prompt:"La maladie de Basedow (Graves) est associée à des anticorps qui :",choices:["Inhibent le récepteur de la TSH","Stimulent le récepteur de la TSH (anti-RTSH stimulants) → hyperthyroïdie","Détruisent les cellules folliculaires (cytotoxiques)","Sont anti-TPO uniquement"],answer:1,diff:2,explication:"Basedow = principale cause d'hyperthyroïdie auto-immune. Anti-RTSH stimulants (= TRAK, TSHRAb) se fixent sur le récepteur TSH et miment l'action de la TSH → stimulation permanente de la thyroïde → hyperthyroïdie + goître diffus + exophtalmie. Le taux de TRAK corrèle avec l'activité et le risque de rechute après traitement.",tags:["Basedow","Hyperthyroïdie","Anti-RTSH","TRAK"]},
  {id:"bm_ip6",prompt:"Les anticorps ANCA (anti-cytoplasme des neutrophiles) de type c-ANCA (pattern cytoplasmique) sont dirigés contre :",choices:["La myéloperoxydase (MPO)","La protéinase 3 (PR3), associés à la granulomatose avec polyangéite (Wegener)","L'histidyl-ARNt synthétase (Jo-1)","La topoisomérase I (Scl-70)"],answer:1,diff:2,explication:"c-ANCA = anti-PR3 (protéinase 3) → granulomatose avec polyangéite (ex-Wegener) : vascularite des gros et moyens vaisseaux, granulomes. p-ANCA (pattern périnucléaire) = anti-MPO → polyangéite microscopique, glomérulonéphrite à pauci-immuns, syndrome de Churg-Strauss. Les ANCA guident le diagnostic et le suivi de ces vascularites systémiques.",tags:["ANCA","PR3","MPO","Vascularites","Wegener"]},
  {id:"bm_ip7",prompt:"En immunohématologie, le test de Coombs DIRECT (TCD) détecte :",choices:["Les anticorps irréguliers circulants dans le sérum du patient","Les immunoglobulines et/ou le complément déjà fixés sur les globules rouges du patient","Les anticorps anti-plaquettes","Les complexes immuns circulants"],answer:1,diff:2,explication:"TCD (test de Coombs direct / DAT = direct antiglobulin test) : ajoute de l'antiglobuline humaine (anti-IgG + anti-C3d) directement sur les GR du patient. Si positif → des Ac ou fractions du complément recouvrent les GR → anémie hémolytique auto-immune (AHAI), maladie hémolytique du nouveau-né (MHN), réaction transfusionnelle hémolytique retardée.",tags:["Coombs direct","AHAI","GR","Immunohématologie"]},
  {id:"bm_ip8",prompt:"Le syndrome des antiphospholipides (SAPL) se caractérise par :",choices:["Un TCA raccourci et des anticorps anti-cardiolipine négatifs","Un TCA allongé (anticoagulant lupique) + anticorps anti-cardiolipine et/ou anti-β2GPI + thromboses et/ou fausses couches répétées","Un TP très allongé et une thrombopénie sévère","Des anticorps anti-ADN natif très élevés uniquement"],answer:1,diff:2,explication:"SAPL = thrombophilie auto-immune. Critères diagnostiques (Sapporo révisé) : ≥ 1 événement clinique (thrombose ou fausse couche ≥ 10 SA) + ≥ 1 test biologique positif à 2 reprises à ≥ 12 semaines : anticoagulant lupique (allonge TCA) + anti-cardiolipine + anti-β2GPI. Paradoxe : l'anticoagulant lupique allonge le TCA mais provoque des THROMBOSES.",tags:["SAPL","Antiphospholipides","TCA","Thrombophilie auto-immune"]},
  {id:"bm_ip9",prompt:"La cryoglobulinémie mixte de type II est très fréquemment associée à :",choices:["L'infection par VIH","L'infection chronique par VHC (hépatite C)","La maladie cœliaque","Le lupus uniquement"],answer:1,diff:2,explication:"Cryoglobulinémie = immunoglobulines précipitant à froid (< 37°C). Type I = Ig monoclonale pure (hémopathie). Type II = complexe IgM monoclonale (souvent FR+) + IgG polyclonale → 90% associées au VHC. Type III = Ig polyclonales. Manifestations : purpura vasculaire, arthralgies, neuropathie, glomérulonéphrite membranoproliférative.",tags:["Cryoglobulinémie","VHC","Immunoglobulines","Vascularite"]},
  {id:"bm_ip10",prompt:"L'électrophorèse des protéines sériques (EPPS) montre un pic étroit en zone gamma. L'étape suivante est :",choices:["Répéter l'EPPS dans 6 mois sans autre exploration","Réaliser une immunofixation pour identifier et typer l'immunoglobuline monoclonale","Doser uniquement les IgG totaux","Faire un myélogramme immédiatement"],answer:1,diff:2,explication:"Pic gamma étroit = suspicion de gammapathie monoclonale. L'immunofixation (électrophorèse + incubation avec anti-IgG, anti-IgA, anti-IgM, anti-κ, anti-λ) permet d'identifier précisément l'isotype. Si IgG < 30 g/L + plasmocytes < 10% = MGUS (surveiller). Si > 30 g/L ou symptoms = myélome → BOM, autres critères CRAB.",tags:["Électrophorèse protéines","Gammapathie monoclonale","Immunofixation","Myélome"]},
  {id:"bm_ip11",prompt:"Les anti-CCP (anticorps anti-peptides citrullinés) dans la polyarthrite rhumatoïde ont une spécificité de :",choices:["~50%, peu utiles au diagnostic","~95-98%, très spécifiques, peuvent précéder les symptômes de plusieurs années","~70%, comparable au facteur rhumatoïde","~30%, dépistage seulement"],answer:1,diff:2,explication:"Anti-CCP (2e génération, ACPA) : spécificité PR > 95%, sensibilité 67-70%. Avantages vs FR : plus spécifiques, peuvent être positifs AVANT les symptômes articulaires (jusqu'à 10 ans avant), prédictifs de l'érosivité articulaire. Association anti-CCP + FR = haute probabilité de PR. Technique ELISA.",tags:["Anti-CCP","Polyarthrite rhumatoïde","ACPA","Diagnostic"]},
  {id:"bm_ip12",prompt:"La diminution concomitante du C3 et du C4 sériques oriente vers :",choices:["Un déficit génétique en C3 uniquement","Une activation de la voie classique du complément (LES, cryoglobulinémie, GN endo-capillaire)","Une activation de la voie alterne uniquement","Un syndrome néphrotique"],answer:1,diff:3,explication:"C3 + C4 bas = activation voie classique (Ag-Ac → C1q → C4 → C2 → C3). Causes : LES actif (marqueur de poussée), cryoglobulinémie, GN membranoproliférative. C3 bas + C4 normal = activation voie alterne (GN à dépôts denses, SHU atypique). CH50 effondré = déficit total ou activation massive. Suivi thérapeutique LES : normalisation C3/C4 + baisse anti-ADN.",tags:["Complément","C3","C4","LES","Voie classique"]},
];

export const QB_BM_MICRO_BM = [
  {id:"bm_mb1",prompt:"Les hémocultures doivent être prélevées :",choices:["Après l'administration des antibiotiques pour éviter les faux négatifs","Avant tout antibiothérapie, au pic fébrile ou de frisson, en 2-3 flacons aéro-anaérobies","En une seule série uniquement","Exclusivement sur cathéter veineux central"],answer:1,diff:1,explication:"Hémocultures : avant ATB (si possible dans les 45 min sinon faire avant la prochaine dose), au pic fébrile (bactériémie maximale). 2-3 paires aérobie+anaérobie → augmente sensibilité à 80-95%. Volume optimal : 8-10 mL/flacon adulte. Délai de positivité : 12-72h (automates BACTEC, BacT/Alert à détection de CO₂).",tags:["Hémocultures","Sepsis","Bactériémie","Prélèvement"]},
  {id:"bm_mb2",prompt:"La bactérie SARM (Staphylococcus aureus résistant à la méticilline) est identifiée par :",choices:["Sa résistance aux carbapénèmes","Sa résistance aux bêtalactamines par le gène mecA/mecC (PLP2a de faible affinité)","Sa production de bêtalactamase à spectre élargi (BLSE)","Sa résistance aux polymyxines"],answer:1,diff:2,explication:"SARM = résistance à la méticilline (et toutes les bêtalactamines) par acquisition du gène mecA (ou mecC) → production de PLP2a (= PBP2a) de très faible affinité pour les bêtalactamines. Détection : disque céfoxitine + PCR mecA en confirmation. Traitement : vancomycine, linézolide, daptomycine (selon l'infection).",tags:["SARM","mecA","Résistance","Staphylocoque"]},
  {id:"bm_mb3",prompt:"Une entérobactérie BLSE (à bêtalactamase à spectre élargi) est résistante à :",choices:["Les aminosides uniquement","Les céphalosporines de 3e génération (C3G), pénicillines + inhibiteurs, et souvent les fluoroquinolones","Les carbapénèmes uniquement","L'imipénème et le méropénème"],answer:1,diff:2,explication:"BLSE = enzyme plasmidique hydrolysant C3G, C4G, aztréonam. Test de synergie : double disque (C3G + amoxicilline-aclavulanate) → image d'oeuf. Les carbapénèmes restent actifs (sauf si KPC/OXA48 associé). Espèces productrices : E. coli, K. pneumoniae, E. cloacae. BMR à surveiller (contact precautions).",tags:["BLSE","C3G","Entérobactéries","Résistance aux antibiotiques"]},
  {id:"bm_mb4",prompt:"Le milieu ALOA est utilisé pour la recherche de :",choices:["Salmonella spp. dans les selles","Listeria monocytogenes dans les aliments et les prélèvements cliniques","Mycobacterium tuberculosis dans les crachats","Clostridium difficile dans les selles"],answer:1,diff:1,explication:"ALOA (Agar Listeria selon Ottaviani et Agosti) = milieu chromogène sélectif + différentiel pour Listeria. L. monocytogenes : colonies bleues-vertes avec halo opaque (activité PI-PLC + LPLA). Sensibilité excellente. Utilisé selon ISO 11290-1 (détection) et 11290-2 (dénombrement). Norme CE 2073/2005 pour aliments.",tags:["ALOA","Listeria","Milieu chromogène","Sécurité alimentaire"]},
  {id:"bm_mb5",prompt:"La résistance aux carbapénèmes chez K. pneumoniae par production de KPC signifie :",choices:["Résistance par imperméabilité membranaire uniquement","Production d'une carbapénémase (bêtalactamase hydrolysant les carbapénèmes) codée par un gène transmissible (plasmide)","Hyperproduction de céphalosporinase chromosomique","Modification des porines uniquement"],answer:1,diff:3,explication:"Carbapénémases (enzymes hydrolysant les carbapénèmes) : KPC (Klebsiella pneumoniae carbapenemase, classe A), NDM (New Delhi Metallo-β-lactamase, classe B), OXA-48 (classe D). Gènes transférables par plasmide → dissémination épidémique. EPC (entérobactéries productrices de carbapénémases) = urgence infectieuse. Dépistage : tests phénotypiques + confirmation moléculaire.",tags:["KPC","Carbapénémase","EPC","Résistance critique"]},
  {id:"bm_mb6",prompt:"La méthode de référence pour l'antibiogramme en France suit les recommandations de :",choices:["CLSI (américain, zones de diamètres)","EUCAST (European Committee on Antimicrobial Susceptibility Testing) avec catégories S/I/R","FDA (américain, MIC uniquement)","OMS (avec catégories Access/Watch/Reserve uniquement)"],answer:1,diff:1,explication:"EUCAST = référentiel européen, adopté en France par le CA-SFM. Méthode des disques sur Mueller-Hinton → diamètre d'inhibition → catégories S (sensible, posologie standard), I (sensible pour posologie forte/site d'infection), R (résistant). Tableaux mis à jour annuellement. Remplace l'ancienne catégorie 'intermédiaire' par 'sensible augmenté'.",tags:["EUCAST","Antibiogramme","S/I/R","Mueller-Hinton"]},
  {id:"bm_mb7",prompt:"La sérologie VIH en France repose sur un test de dépistage de 4e génération qui détecte :",choices:["Les Ac anti-VIH uniquement (3e génération)","Les Ac anti-VIH + l'antigène p24 (Ag-Ac combiné, 4e génération)","L'ARN viral (charge virale)","Les Ac anti-gp120 uniquement"],answer:1,diff:1,explication:"Test combiné Ag-Ac (4e génération) : détecte simultanément l'Ag p24 (présent dès J10-15 post-contamination) + Ac anti-VIH (présents à partir de J21-28). Fenêtre sérologique réduite à ~18 jours. Résultat positif confirmé par Western blot. Charge virale ARN VIH = suivi thérapeutique et diagnostic périnatal.",tags:["VIH","Sérologie 4G","Ag p24","Dépistage"]},
  {id:"bm_mb8",prompt:"La PCR du gène 16S de l'ARN ribosomique est utilisée en microbiologie pour :",choices:["Détecter uniquement les bactéries Gram positif","Identifier les bactéries par comparaison de la séquence à une base de données (identification universelle et typage moléculaire)","Mesurer la charge virale","Détecter les résistances aux antibiotiques"],answer:1,diff:2,explication:"Le gène 16S ARNr (1550 paires de bases) contient des régions conservées (amorces universelles) + des régions variables (V1-V9) permettant l'identification de l'espèce. Séquençage + comparaison aux bases SILVA, NCBI → identification en quelques heures même pour espèces non cultivables ou à croissance lente. Application : métagénomique, identification de l'écosystème microbien intestinal.",tags:["PCR 16S","Identification bactérienne","Métagénomique","Séquençage"]},
  {id:"bm_mb9",prompt:"L'ECBU est positif (infection urinaire avérée) quand on retrouve :",choices:["Uniquement leucocyturie ≥ 10⁴/mL sans bactérie","Leucocyturie ≥ 10⁴/mL ET bactériurie ≥ 10⁵ UFC/mL (ou ≥ 10³ si S. saprophyticus ou cathéter)","Bactériurie ≥ 10³ UFC/mL seule sans leucocytes","Nitrites positifs seuls à la bandelette"],answer:1,diff:1,explication:"ECBU : recueil mi-jet, traitement < 2h (ou + 4°C). Seuil infection : leucocyturie ≥ 10⁴/mL (= 10 leucocytes/µL) + bactériurie ≥ 10⁵ UFC/mL (E. coli). Seuils abaissés pour S. saprophyticus (10³), prélevements sur cathéter. BU (bandelette urinaire) : valeur prédictive négative élevée si leucocytes ET nitrites négatifs → exclut l'IU.",tags:["ECBU","Infection urinaire","Leucocyturie","Bactériurie"]},
  {id:"bm_mb10",prompt:"Les carbapénèmes (imipénème, méropénème) ont pour spectre d'activité :",choices:["Uniquement les Gram positifs","Pratiquement toutes les bactéries aérobies Gram+ et Gram-, y compris les BLSE et anaérobies (spectre ultra-large)","Uniquement les Pseudomonas et Acinetobacter","Les anaérobies uniquement"],answer:1,diff:2,explication:"Carbapénèmes = bêtalactamines à spectre ultra-large, actifs sur : Gram+ (sauf SARM, ERV), Gram- (y compris entérobactéries BLSE, Pseudomonas, Acinetobacter), anaérobies. Antibiotiques de dernier recours (last resort). Réservés aux infections sévères à BMR. Menace des EPC (entérobactéries productrices de carbapénémases).",tags:["Carbapénèmes","Spectre large","Antibiotiques","BMR"]},
  {id:"bm_mb11",prompt:"L'examen direct d'un LCR (liquide céphalorachidien) en urgence comprend :",choices:["Uniquement la culture bactérienne (résultat en 24h)","Cytologie (leucocytes, hématies), biochimie (glucose, protéines) et examen microscopique direct (bactériologie + Gram)","L'antibiogramme immédiat","La sérologie VIH"],answer:1,diff:1,explication:"LCR normal : < 5 cellules/µL (lymphocytes), protéines < 0.45 g/L, glucose > 50% glycémie. Méningite bactérienne : polynucléaires > 1000/µL, protéines ↑↑, glucose ↓↓ (< 40% glycémie), Gram + (cocci en diplocoques → pneumocoque, méningocoques ; bacilles → Listeria). Méningite virale : lymphocytes, glucose normal, protéines légèrement ↑.",tags:["LCR","Méningite","Examen direct","Urgence"],},
  {id:"bm_mb12",prompt:"Le test PCR Xpert MTB/RIF est utilisé pour :",choices:["Dépister la BLSE dans les selles","Détecter Mycobacterium tuberculosis + résistance à la rifampicine (marqueur multirésistance) en < 2 heures","Identifier Clostridium difficile","Mesurer la charge virale VHC"],answer:1,diff:2,explication:"Xpert MTB/RIF (GeneXpert, Cepheid) : PCR nichée en temps réel en cartouche automatisée. Résultat en 2h. Détecte ADN de M. tuberculosis + mutations du gène rpoB (90% des résistances à la rifampicine = marqueur MDR-TB). Recommandé par OMS en 1ère intention si suspicion tuberculose. Sensibilité ≈ 88% (expectorations), < 70% (LCR, biopsies).",tags:["Xpert MTB/RIF","Tuberculose","MDR-TB","PCR rapide"]},
];

export const QB_BM_GENETIQUE = [
  {id:"bm_ge1",prompt:"Le caryotype standard analyse les chromosomes à partir de :",choices:["GR (globules rouges) en métaphase","Lymphocytes du sang périphérique en culture, bloqués en métaphase (colcémide), colorés en GTG","Cellules musculaires","Plaquettes"],answer:1,diff:1,explication:"Caryotype = analyse chromosomique. Lymphocytes prélevés en sang veineux, mis en culture 72h avec phytohémagglutinine (PHA) pour stimuler les mitoses, bloqués en métaphase (colcémide = poison du fuseau), hypotonie, fixation, étalement, coloration GTG (Giemsa Trypsine Giemsa) → bandes sombres/claires. Résultat : 46,XX ou 46,XY normal.",tags:["Caryotype","Lymphocytes","GTG","Métaphase"]},
  {id:"bm_ge2",prompt:"La trisomie 21 (syndrome de Down) est le plus souvent due à :",choices:["Une translocation robertsonienne t(14;21) dans 95% des cas","Une non-disjonction méiotique → trisomie libre 47,+21, dans 95% des cas","Une délétion du chromosome 21","Une mutation ponctuelle du gène DYRK1A"],answer:1,diff:2,explication:"T21 : 95% trisomie libre (47,XX ou XY,+21) → non-disjonction en méiose I maternelle (↑ risque avec âge maternel). 4% translocation robertsonienne (fusion chr 14 et 21) → risque de récurrence ++ → conseil génétique impératif. 1% mosaïque (phénotype souvent moins sévère). Dépistage prénatal : clarté nucale T1 + DPNI (ADN fœtal libre).",tags:["Trisomie 21","Caryotype","Non-disjonction","Dépistage prénatal"]},
  {id:"bm_ge3",prompt:"Le test DPNI (Dépistage Prénatal Non Invasif) repose sur :",choices:["Une biopsie placentaire (choriocentèse)","L'analyse de l'ADN fœtal libre circulant dans le sang maternel (cffDNA, > 10% de l'ADN maternel)","Un caryotype fœtal direct","La mesure de l'AFP maternelle uniquement"],answer:1,diff:2,explication:"DPNI = analyse de l'ADN fœtal libre (cffDNA, origin placentaire) présent dans la circulation maternelle à partir de la 10e semaine. Sensibilité > 99% pour T21, T18, T13. Remplace les anciennes combinaisons de marqueurs sériques. En France depuis 2018 en 2e recours après dépistage combiné T1. Un résultat positif doit être confirmé par examen invasif (amniocentèse ou choriocentèse).",tags:["DPNI","ADN fœtal","Dépistage","Trisomie"]},
  {id:"bm_ge4",prompt:"La mucoviscidose est une maladie autosomique récessive due à des mutations du gène :",choices:["BRCA1","CFTR (Cystic Fibrosis Transmembrane conductance Regulator)","DMD (dystrophine)","HTT (huntingtine)"],answer:1,diff:1,explication:"CFTR : canal chlorure épithélial. Mutation F508del = 70% des allèles en France. Autosomique récessive → 1 malade pour 4 enfants de deux porteurs. Manifestations : bronchopneumopathies chroniques, insuffisance pancréatique exocrine, infertilité masculine (agénésie des canaux déférents). Diagnostic : test de la sueur (Cl⁻ > 60 mmol/L) + génotypage CFTR.",tags:["Mucoviscidose","CFTR","F508del","Autosomique récessif"]},
  {id:"bm_ge5",prompt:"Les mutations germinales BRCA1/BRCA2 augmentent le risque de :",choices:["Leucémie myéloïde chronique","Cancer du sein (60-80%) et cancer de l'ovaire (40-60%)","Polypes adénomateux colorectaux","Phéochromocytome"],answer:1,diff:1,explication:"BRCA1 (chr 17) et BRCA2 (chr 13) = gènes suppresseurs de tumeur, impliqués dans la réparation de l'ADN par recombinaison homologue. Mutations germinales → HBOC (Hereditary Breast and Ovarian Cancer). Risque vie entière : sein 60-80%, ovaire 40% (BRCA1) ou 15% (BRCA2). Indication thérapie ciblée : inhibiteurs PARP (olaparib) si mutation BRCA. Conseil génétique avant test.",tags:["BRCA1","BRCA2","Cancer du sein","Oncogénétique"]},
  {id:"bm_ge6",prompt:"Le syndrome de Lynch (HNPCC) est dû à des mutations dans les gènes :",choices:["RB1 et TP53","MMR (MLH1, MSH2, MSH6, PMS2) impliqués dans la réparation des mésappariements de l'ADN","BRCA1 et BRCA2","APC et KRAS"],answer:1,diff:2,explication:"Syndrome de Lynch = HNPCC (Hereditary Non-Polyposis Colorectal Cancer). Mutations des gènes MMR (MisMatch Repair) → accumulation de mutations dans les microsatellites → instabilité microsatellitaire (MSI). Risque CCR cumulé 50-80%, mais aussi endomètre (40-60%), ovaire, urothélial. Dépistage : IHC MMR sur pièce opératoire → perte d'expression si mutation. Suivi : coloscopie tous les 2 ans dès 25 ans.",tags:["Syndrome de Lynch","HNPCC","MMR","MSI"]},
  {id:"bm_ge7",prompt:"L'instabilité microsatellitaire haute (MSI-H) sur une tumeur colorectale est un marqueur prédictif de réponse aux :",choices:["Chimiothérapies à base de 5-fluorouracile uniquement","Inhibiteurs de checkpoint immunitaire (anti-PD1 : pembrolizumab, nivolumab)","Thérapies ciblées anti-EGFR (cétuximab, panitumumab)","Radiothérapie exclusive"],answer:1,diff:3,explication:"MSI-H = dysfonction de la voie MMR → hyper-mutation → néoantigènes ++ → immunogénicité élevée. Les anti-PD1 sont particulièrement efficaces dans les tumeurs MSI-H tous types confondus (colorectal, endomètre, gastrique…). Le pembrolizumab est approuvé en 1ère ligne pour les CCR MSI-H. À l'inverse, les anti-EGFR ne sont efficaces que si KRAS/NRAS/BRAF sauvages.",tags:["MSI","Immunothérapie","Anti-PD1","Cancer colorectal"]},
  {id:"bm_ge8",prompt:"La FISH (Fluorescence In Situ Hybridization) permet de détecter :",choices:["Toutes les mutations ponctuelles sans exception","Des anomalies chromosomiques ciblées (translocations, amplifications, délétions) en utilisant des sondes fluorescentes sur noyaux en interphase ou métaphase","Le méthylome complet d'une tumeur","Les variants de séquence à l'échelle nucléotidique"],answer:1,diff:2,explication:"FISH : sondes fluorescentes complémentaires de régions chromosomiques spécifiques → hybridation sur noyaux (interphase FISH = rapide, pas besoin de mitoses). Applications : t(9;22) BCR-ABL (LMC), amplification HER2 (sein), t(14;18) (lymphome folliculaire), délétion 17p (LLC), anomalies 1p/19q (gliome). Résultat en 24-48h. CGH-array = détecte tous les CNV génomiques.",tags:["FISH","Anomalies chromosomiques","HER2","Oncologie"]},
  {id:"bm_ge9",prompt:"Le NGS (Next Generation Sequencing) en oncologie est utilisé pour :",choices:["Analyser uniquement le gène TP53","Identifier les mutations somatiques actionnables (KRAS, EGFR, BRAF, ALK, HER2…) guidant les thérapies ciblées, et détecter les résistances","Doser les marqueurs tumoraux sériques","Effectuer un caryotype haute résolution"],answer:1,diff:2,explication:"NGS en oncologie (tumeur solide) : panels de gènes (50-500 gènes) ou WES → identification mutations somatiques actionnables → thérapie ciblée ou immunothérapie adaptée (médecine de précision). Ex : mutation EGFR (exon 19/21) → erlotinib/osimertinib (CBNPC) ; BRAF V600E → vémurafénib (mélanome). Aussi : ADN tumoral circulant (ctDNA) en biopsie liquide.",tags:["NGS","Oncologie moléculaire","Thérapie ciblée","Médecine de précision"]},
  {id:"bm_ge10",prompt:"La pharmacogénomique du CYP2D6 concerne notamment le métabolisme de :",choices:["L'aspirine (acide acétylsalicylique)","La codéine (pro-drogue transformée en morphine par CYP2D6, risque de surdosage chez les métaboliseurs ultra-rapides)","L'amoxicilline","Le paracétamol"],answer:1,diff:2,explication:"CYP2D6 : 4 phénotypes : métaboliseur lent (ML, 7% Caucasiens) = accumulation du médicament, toxicité ; extensive (ME, normal) ; intermédiaire (MI) ; ultra-rapide (MU, 5-10%, amplification gène) = métabolisme accéléré, manque d'effet ou sur-production métabolite actif. Codéine → morphine (CYP2D6) → risque dépression respiratoire chez MU. Statuts DPYD, TPMT, UGT1A1 aussi importants en oncologie.",tags:["Pharmacogénomique","CYP2D6","Codéine","Métabolisme médicaments"]},
  {id:"bm_ge11",prompt:"Le test génétique constitutionnel (recherche de mutation germinale) exige en France :",choices:["Aucune formalité particulière, résultat remis directement","Un consentement éclairé écrit du patient ET un conseil génétique (consultation avant ET après) + prescription par médecin habilité","Seulement une ordonnance médicale standard","Uniquement l'accord du directeur de l'hôpital"],answer:1,diff:1,explication:"Loi bioéthique française (2021) : examen des caractéristiques génétiques constitutionnelles → consentement éclairé écrit obligatoire (formulaire spécifique) + consultation génétique (médecin qualifié en génétique) avant et après le test. Prescription uniquement par médecin. Le résultat est rendu au patient par le médecin prescripteur lors d'une consultation dédiée. Droit de ne pas savoir.",tags:["Génétique constitutionnelle","Consentement","Conseil génétique","Loi bioéthique"]},
  {id:"bm_ge12",prompt:"La PCR digitale en gouttelettes (ddPCR) est particulièrement utile pour :",choices:["Le génotypage de routine des groupes sanguins","La détection ultrasensible de mutations rares (ADN tumoral circulant < 0.1%) ou la quantification absolue de charge virale","L'identification morphologique des chromosomes","La séquençage de novo de génomes bactériens"],answer:1,diff:3,explication:"ddPCR (droplet digital PCR) : compartimentalisation de la réaction en milliers de gouttelettes → résultat : nombre de gouttelettes positives/totales = concentration absolue sans courbe étalon. Sensibilité extrême (détecte 1 copie mutée dans 10 000 copies sauvages = 0.01%). Applications : biopsie liquide (ctDNA, MRD leucémie), mesure résiduelle de la maladie, quantification charge virale ultra-basse.",tags:["ddPCR","PCR digitale","ctDNA","Biopsie liquide"]},
];

export const QB_BM_ACIDO_BASIQUE = [
  {id:"bm_ab1",prompt:"Le pH sanguin artériel normal est compris entre :",choices:["7,20 et 7,30","7,35 et 7,45","7,50 et 7,60","7,60 et 7,80"],answer:1,diff:1,explication:"pH artériel normal : 7,40 ± 0,05 (soit 7,35-7,45). En dessous de 7,35 = acidémie ; au-dessus de 7,45 = alcalémie. À pH 7,40, [H+] = 40 nmol/L. Une variation de 0,3 unité pH correspond à un doublement ou une division par 2 de [H+].",tags:["pH","EAB","Valeurs normales"]},
  {id:"bm_ab2",prompt:"Le système tampon bicarbonate représente environ quelle fraction des tampons sanguins ?",choices:["20%","40%","65%","90%"],answer:2,diff:2,explication:"Le système bicarbonate (H2CO3/HCO3-) représente ~65% de la capacité tampon totale du plasma. Avantage : les deux composants sont régulables indépendamment (CO2 par le poumon, HCO3- par le rein). Henderson-Hasselbalch : pH = 6,1 + log([HCO3-] / 0,03 × PaCO2).",tags:["Tampons","Bicarbonate","Henderson-Hasselbalch"]},
  {id:"bm_ab3",prompt:"L'effet Bohr correspond à :",choices:["L'augmentation de l'affinité de l'Hb pour O2 quand le pH diminue","La diminution de l'affinité de l'Hb pour O2 quand le pH diminue (acidose → libération O2 dans les tissus)","L'augmentation de la solubilité du CO2 à haute pression","La fixation préférentielle du CO2 sur les globules rouges"],answer:1,diff:2,explication:"Effet Bohr : ↓ pH (acidose) → ↓ affinité Hb-O2 → courbe de dissociation décalée vers la droite → meilleure libération d'O2 aux tissus. Effet Haldane = HbO2 libère CO2 au poumon. Effet Hamburger = échange Cl-/HCO3- transmembranaire.",tags:["Effet Bohr","Hémoglobine","O2","pH"]},
  {id:"bm_ab4",prompt:"Dans l'acidose respiratoire aiguë, la compensation métabolique consiste en :",choices:["Hyperventilation pour éliminer le CO2","Rétention rénale de HCO3- (augmentation de la réabsorption et de la synthèse rénale)","Excrétion rénale de HCO3-","Diminution de la ventilation"],answer:1,diff:2,explication:"Acidose respiratoire = PaCO2 ↑ → pH ↓. Compensation métabolique (rénale, lente : 3-5 jours) : ↑ réabsorption HCO3- + ↑ excrétion NH4+ → ↑ HCO3- plasmatique → correction partielle du pH. La compensation ventilatoire est impossible (la cause EST respiratoire).",tags:["Acidose respiratoire","Compensation","HCO3-","Rein"]},
  {id:"bm_ab5",prompt:"L'acidose métabolique se définit biologiquement par :",choices:["PaCO2 > 45 mmHg + pH < 7,35","HCO3- < 22 mmol/L + pH < 7,35","HCO3- > 26 mmol/L + pH < 7,35","PaO2 < 60 mmHg + pH < 7,35"],answer:1,diff:1,explication:"Acidose métabolique : HCO3- primitivement bas (< 22 mmol/L) → pH < 7,35. Compensation respiratoire immédiate : hyperventilation → ↓ PaCO2. Formule de Winter : PaCO2 attendu = 1,5 × [HCO3-] + 8 ± 2. Causes à trou anionique élevé (MUDPILES) : méthanol, urémie, acido-cétose, lactates, éthylène glycol, salicylates.",tags:["Acidose métabolique","HCO3-","Trou anionique","Formule de Winter"]},
  {id:"bm_ab6",prompt:"Le trou anionique (TA) plasmatique normal est :",choices:["0-4 mEq/L","8-12 mEq/L","15-20 mEq/L","25-30 mEq/L"],answer:1,diff:2,explication:"TA = Na+ - (Cl- + HCO3-) = 8-12 mEq/L (anions non mesurés : albumine, phosphates, sulfates). TA augmenté > 16 → acidose par accumulation d'acides. TA normal → acidose par perte de HCO3- (diarrhée, acidose tubulaire rénale). TA corrigé si hypoalbuminémie : TA corrigé = TA mesuré + 2,5 × (4 - albumine g/dL).",tags:["Trou anionique","Acidose métabolique","Électrolytes"]},
  {id:"bm_ab7",prompt:"L'électrode de Severinghaus mesure spécifiquement :",choices:["Le pH sanguin direct par électrode de verre","La PaCO2 (via mesure du pH d'une solution bicarbonatée séparée par une membrane perméable au CO2)","La PaO2 par réduction de l'oxygène sur cathode polarisée","Le pH urinaire par indicateur coloré"],answer:1,diff:3,explication:"Électrode de Severinghaus (1958) mesure la PaCO2 : membrane perméable au CO2 → diffusion dans solution NaHCO3 interne → modification pH mesurée par électrode de verre. PaO2 : électrode de Clark (cathode polarisée). pH direct : électrode de verre (potentiel Nernst). Les 3 électrodes constituent l'analyseur de gaz du sang.",tags:["Severinghaus","PaCO2","Gazométrie","Électrodes"]},
  {id:"bm_ab8",prompt:"L'alcalose métabolique par vomissements est souvent associée à :",choices:["Une hyperkaliémie et hyperchlorémie","Une hypokaliémie et hypochlorémie","Une hyperkaliémie et hypochlorémie","Une hypokaliémie et hyperchlorémie"],answer:1,diff:2,explication:"Alcalose métabolique par vomissements : perte HCl → ↑ HCO3- + ↓ Cl- (hypochlorémie). L'aldostérone (activée par hypovolémie) → réabsorbe Na+ + échange K+/H+ → hypokaliémie + excrétion H+ (alcalose de maintenance). Traitement : NaCl + KCl.",tags:["Alcalose métabolique","Hypokaliémie","Hypochlorémie","Vomissements"]},
  {id:"bm_ab9",prompt:"La valeur normale de la PaCO2 artérielle est :",choices:["20-25 mmHg","35-45 mmHg","50-60 mmHg","60-70 mmHg"],answer:1,diff:1,explication:"PaCO2 normale = 35-45 mmHg (moyenne 40 mmHg). Hypercapnie > 45 mmHg : hypoventilation alvéolaire, cause respiratoire d'acidose. Hypocapnie < 35 mmHg : hyperventilation (compensation acidose métabolique ou alcalose respiratoire primitive). PaO2 normale : 80-100 mmHg.",tags:["PaCO2","Gazométrie","Valeurs normales"]},
  {id:"bm_ab10",prompt:"Dans quel trouble trouve-t-on pH < 7,35, PaCO2 < 35 mmHg et HCO3- < 22 mmol/L ?",choices:["Acidose respiratoire compensée","Acidose métabolique compensée (hyperventilation réactionnelle)","Alcalose respiratoire décompensée","Trouble mixte : acidose respiratoire + alcalose métabolique"],answer:1,diff:3,explication:"Acidose métabolique compensée : HCO3- bas (cause) → pH bas → hyperventilation compensatrice → PaCO2 basse. Le pH reste < 7,35 (la compensation est incomplète). Formule de Winter : PaCO2 attendue = 1,5 × [HCO3-] + 8 ± 2. Si PaCO2 < attendue → alcalose respiratoire surajoutée (trouble mixte).",tags:["Acidose métabolique","Compensation","Trouble mixte","EAB"]},
];

export const QB_BM_REPRODUCTION = [
  {id:"bm_rp1",prompt:"La phase lutéale d'un cycle menstruel dure :",choices:["5 jours (variable)","14 jours (FIXE — durée de vie du corps jaune)","21 jours (variable)","7 jours (variable)"],answer:1,diff:1,explication:"Phase lutéale (J14-J28) : FIXE à 14 jours (durée de vie du corps jaune). C'est la phase folliculaire qui est variable (10-20 jours). Corps jaune → progestérone (hyperthermiant). Si pas de grossesse : régression du corps jaune → chute progestérone/oestrogènes → menstruations.",tags:["Cycle menstruel","Phase lutéale","Corps jaune","Progestérone"]},
  {id:"bm_rp2",prompt:"L'hormone anti-müllérienne (AMH) est utilisée pour évaluer :",choices:["La qualité ovocytaire","La réserve ovarienne (stock folliculaire restant)","Le risque de syndrome des ovaires polykystiques uniquement","L'âge de la ménopause future avec précision"],answer:1,diff:1,explication:"AMH : sécrétée par les cellules de la granulosa des follicules préantraux/antraux. Reflète le stock folliculaire : ↓ AMH = réserve diminuée. Valeurs normales : 1-53 ng/mL selon l'âge (pic 20-25 ans). Stable tout au long du cycle : peut se doser à n'importe quel jour. Utilisée en bilan d'infertilité et dans le SOPK (AMH très élevée).",tags:["AMH","Réserve ovarienne","Infertilité","FIV"]},
  {id:"bm_rp3",prompt:"La progestérone dosée au J21 du cycle permet de :",choices:["Confirmer l'ovulation (progestérone > 16-30 nmol/L = ovulation survenue)","Dépister un cancer de l'ovaire","Évaluer la réserve ovarienne","Détecter une grossesse débutante"],answer:0,diff:2,explication:"Dosage progestérone J21 (7j après ovulation J14) : > 16-30 nmol/L → ovulation confirmée. < 10 nmol/L → anovulation. En cas de cycle long, doser 7 jours avant les règles prévues. La progestérone est produite par le corps jaune post-ovulatoire. La progestérone est également hyperthermiant : plateau thermique de +0,3-0,5°C en phase lutéale.",tags:["Progestérone","Ovulation","Corps jaune","J21"]},
  {id:"bm_rp4",prompt:"La courbe de température basale biphasique (plateau thermique) est liée à :",choices:["L'oestradiol qui est hyperthermiant","La progestérone hyperthermiant (action centrale hypothalamique)","La LH qui déclenche l'ovulation","La FSH qui stimule la croissance folliculaire"],answer:1,diff:1,explication:"Progestérone (corps jaune post-ovulatoire) : effet hyperthermiant central (hypothalamus). Élévation de 0,3-0,5°C en 2e partie de cycle. Retour à la normale à J28 si pas de grossesse. Persistance du plateau > 18j → évocateur de grossesse. Les oestrogènes sont légèrement hypothermiants.",tags:["Progestérone","Température basale","Oestrogènes","Cycle"]},
  {id:"bm_rp5",prompt:"Le seuil discriminant de la β-HCG permettant de visualiser une grossesse intra-utérine en échographie endo-vaginale est :",choices:["β-HCG > 100 UI/L","β-HCG > 1000-1500 UI/L","β-HCG > 10 000 UI/L","β-HCG > 100 000 UI/L"],answer:1,diff:2,explication:"β-HCG produite par le syncytiotrophoblaste dès la nidation (J6-8). Détectable en sérum dès J9-10. Seuil discriminant : 1000-1500 UI/L → sac gestationnel visible en échographie endo-vaginale. Absence de sac pour β-HCG > 2000 + absence grossesse IU → évoquer GEU. Pic : 8-10 SA (~100 000 UI/L).",tags:["β-HCG","Grossesse","Seuil discriminant","GEU"]},
  {id:"bm_rp6",prompt:"L'ICSI est indiquée en priorité par rapport à la FIV classique dans :",choices:["L'infertilité inexpliquée < 2 ans","L'oligozoospermie sévère, l'azoospermie (recueil chirurgical) ou les échecs de FIV","La stérilité tubaire bilatérale","L'endométriose minime"],answer:1,diff:1,explication:"ICSI : injection directe d'un spermatozoïde dans l'ovocyte. Indications : OATS sévère, azoospermie (TESE/MESA), échec de FIV. FIV classique : infertilité tubaire, endométriose, infertilité inexpliquée. IMSI = ICSI à fort grossissement (× 6000) pour sélectionner la meilleure morphologie nucléaire.",tags:["ICSI","FIV","AMP","OATS"]},
  {id:"bm_rp7",prompt:"La définition médicale de l'infertilité du couple est :",choices:["Absence de grossesse après 6 mois","Absence de grossesse après 12 mois de rapports non protégés réguliers (ou 6 mois si > 35 ans)","Absence de grossesse après 24 mois","Stérilité définitive documentée"],answer:1,diff:1,explication:"Définition OMS : absence de grossesse après 12 mois de rapports non protégés réguliers. Délai réduit à 6 mois si femme > 35 ans, ou si facteur identifié (aménorrhée, ATCD chlamydia). Bilan de base : spermogramme + bilan hormonal (FSH, LH, E2, AMH, prolactine) + hystérosalpingographie.",tags:["Infertilité","Définition OMS","Bilan","Délai"]},
  {id:"bm_rp8",prompt:"La FSH et l'E2 du bilan d'infertilité féminine sont dosés de préférence :",choices:["En 2e partie de cycle (J21)","En début de cycle (J2-J4), à jeun, le matin","À n'importe quel jour du cycle","Uniquement en cas d'aménorrhée"],answer:1,diff:2,explication:"FSH (J2-J4) : marqueur de réserve ovarienne. FSH > 10 UI/L = réserve diminuée. E2 > 60 pg/mL en J2-J4 → recrutement folliculaire précoce = réserve diminuée. FSH élevée + E2 élevée = ovaire épuisé. L'AMH peut être dosée à tout moment du cycle.",tags:["FSH","E2","Réserve ovarienne","Bilan hormonal"]},
  {id:"bm_rp9",prompt:"Le SOPK (syndrome des ovaires polykystiques) est caractérisé par :",choices:["LH basse + FSH haute + androgènes bas","Rapport LH/FSH > 2 + androgènes élevés + AMH très élevée + anovulation","FSH très haute + LH basse + anovulation","TSH haute + AMH basse"],answer:1,diff:2,explication:"SOPK (critères Rotterdam 2003 : 2/3 sur 3) : irrégularités menstruelles/anovulation + hyperandrogénisme + aspect échographique polykystique. Biologie : LH/FSH > 2, androgènes élevés (testostérone, SDHA), AMH très élevée. Insulinorésistance fréquente. 1ère cause d'infertilité par anovulation.",tags:["SOPK","LH","FSH","AMH","Androgènes","Anovulation"]},
  {id:"bm_rp10",prompt:"Le déclenchement de l'ovulation en FIV est réalisé par :",choices:["Un bolus de FSH recombinante","Une injection de β-HCG (analogue de la LH) ou d'un agoniste GnRH (si protocole antagoniste)","L'arrêt brutal de la progestérone","Une injection d'oestradiol"],answer:1,diff:2,explication:"Déclenchement en FIV : injection β-HCG (mimique le pic LH) ou agoniste GnRH (Décapeptyl® si protocole antagoniste — réduit risque SHO). Ponction ovocytaire 36h après le déclenchement. Risque principal : syndrome d'hyperstimulation ovarienne (SHO).",tags:["FIV","Déclenchement","β-HCG","GnRH","SHO"]},
];

export const QB_BM_SPERMIOLOGIE = [
  {id:"bm_sp1",prompt:"Selon les normes OMS 2010, la concentration minimale normale de spermatozoïdes est :",choices:["5 millions/mL","15 millions/mL (5e percentile population fertile)","50 millions/mL","100 millions/mL"],answer:1,diff:1,explication:"OMS 2010 (5e percentile hommes fertiles) : concentration ≥ 15 × 10⁶/mL (15 millions/mL) ou ≥ 39 millions pour l'éjaculat total. Autres normes : mobilité progressive ≥ 32%, vitalité ≥ 58%, morphologie ≥ 4% (Kruger). Volume éjaculat ≥ 1,5 mL. pH ≥ 7,2.",tags:["Spermogramme","OMS 2010","Concentration","Normes"]},
  {id:"bm_sp2",prompt:"La mobilité progressive (type PR) selon OMS 2010 correspond à :",choices:["Tout spermatozoïde qui se déplace","Les spermatozoïdes se déplaçant activement avec déplacement net vers l'avant (ligne droite ou grands cercles)","Les spermatozoïdes se déplaçant sur place","Les spermatozoïdes immobiles mais vivants"],answer:1,diff:2,explication:"Mobilité Progressive (PR) : déplacement net vers l'avant. Norme ≥ 32%. Mobilité Non Progressive (NP) : mobile sans déplacement net. Mobilité totale (PR + NP) ≥ 40%. Asthénospermie : PR < 32%. OATS = oligo + asthéno + térato combinés.",tags:["Mobilité","OMS 2010","Asthénospermie","OATS"]},
  {id:"bm_sp3",prompt:"La morphologie des spermatozoïdes selon les critères stricts de Kruger est considérée normale si :",choices:["≥ 30% de formes normales","≥ 14% de formes normales","≥ 4% de formes normales (critères stricts de Kruger)","≥ 1% de formes normales"],answer:2,diff:2,explication:"Critères stricts de Kruger (OMS 2010) : morphologie normale ≥ 4%. Tête ovale, acrosome 40-70% de la tête. Tératospermie : < 4%. NB : les critères Kruger sont plus stricts que les anciens critères OMS 1999 (14%).",tags:["Morphologie","Kruger","OMS 2010","Tératospermie"]},
  {id:"bm_sp4",prompt:"Le délai d'abstinence recommandé avant un spermogramme est :",choices:["1 jour","2 à 7 jours (3-5 jours idéalement)","10 à 14 jours","1 mois"],answer:1,diff:1,explication:"Abstinence recommandée : 2-7 jours (idéalement 3-5 jours). < 2 jours = volume réduit, concentration sous-estimée. > 7 jours = ↓ mobilité et ↑ % spermatozoïdes morts. Le délai doit être le même pour les examens successifs.",tags:["Abstinence","Spermogramme","Conditions préanalytiques"]},
  {id:"bm_sp5",prompt:"L'azoospermie se définit par :",choices:["Moins de 1 million de spermatozoïdes/mL","Absence totale de spermatozoïdes dans l'éjaculat (après centrifugation et examen du culot)","Mobilité nulle de tous les spermatozoïdes","Moins de 1% de formes normales"],answer:1,diff:1,explication:"Azoospermie : absence de spermatozoïdes confirmée après centrifugation (1500g, 15 min) et examen du culot. Types : sécrétoire (atrophie testiculaire, FSH élevée) vs obstructive (obstacle sur voies séminales, FSH normale). Diagnostic différentiel par biopsie testiculaire (TESE).",tags:["Azoospermie","Spermogramme","FSH","TESE"]},
  {id:"bm_sp6",prompt:"Le test de vitalité spermatique à l'éosine-nigrosine évalue :",choices:["La fragmentation de l'ADN spermatique","La proportion de spermatozoïdes vivants (membrane intacte = exclusion éosine = incolore = vivant)","La mobilité totale des spermatozoïdes","Le pH de l'éjaculat"],answer:1,diff:2,explication:"Vitalité (éosine-nigrosine) : spermatozoïdes morts → membrane altérée → pénétration éosine → rose/rouge. Vivants : incolores. Norme OMS 2010 : vitalité ≥ 58%. Nécrozospermie : < 58% de vivants. À différencier de l'asthénospermie (mobilité).",tags:["Vitalité","Éosine","Nécrozospermie","OMS 2010"]},
  {id:"bm_sp7",prompt:"La cryptorchidie bilatérale non traitée entraîne :",choices:["Une hyperandrogénie","Une infertilité par atteinte de la spermatogenèse (sensible à la température : 34°C normal vs 37°C intra-abdominal)","Une hypersexualité","Aucune conséquence sur la fertilité"],answer:1,diff:2,explication:"Cryptorchidie : spermatogenèse compromise car elle requiert ~34°C (2-3°C moins que T° corporelle). Cryptorchidie bilatérale non traitée → azoospermie ou oligospermie sévère. Traitement : orchidopexie avant 18 mois. Risque surajouté : cancer testiculaire (× 4-6).",tags:["Cryptorchidie","Spermatogenèse","Infertilité","Orchidopexie"]},
  {id:"bm_sp8",prompt:"La fragmentation de l'ADN spermatique (DFI) est pathologique au-delà de :",choices:["5%","15%","25% (risque élevé d'infertilité et fausses couches)","50%"],answer:2,diff:3,explication:"DFI pathologique > 25% : ↑ fausses couches précoces, ↓ taux de grossesse FIV. DFI > 30-40% : impact sévère. Causes : varicocèle, tabac, oxydation (ROS), chaleur, infections. L'ICSI peut partiellement contourner ce problème.",tags:["Fragmentation ADN","DFI","TUNEL","Fausses couches","ICSI"]},
  {id:"bm_sp9",prompt:"L'OATS sévère est défini par :",choices:["Une seule anomalie : concentration < 15M/mL","L'association des 3 anomalies : oligospermie sévère + asthénospermie + tératospermie","Uniquement une concentration < 1 M/mL","La présence d'anticorps antispermatozoïdes"],answer:1,diff:2,explication:"OATS = Oligo (↓ concentration) + Asthéno (↓ mobilité) + Térato (↓ morphologie). OATS sévère : concentration < 5 M/mL. C'est l'indication principale de l'ICSI. Bilan étiologique : génétique (microdélétions AZFb/c), varicocèle, cryptorchidie.",tags:["OATS","Oligospermie","ICSI","Infertilité masculine"]},
  {id:"bm_sp10",prompt:"La varicocèle altère la fertilité masculine principalement par :",choices:["Obstruction mécanique des canaux déférents","Élévation de la température testiculaire (reflux veineux → ↑ T° → ↑ ROS → altération spermatogenèse)","Déficit en testostérone (cellules de Leydig)","Anticorps antispermatozoïdes en excès"],answer:1,diff:2,explication:"Varicocèle (dilatation veineuse plexus pampiniforme, souvent à gauche) : hyperthermie testiculaire → ↑ ROS → stress oxydant → altération spermatogenèse + fragmentation ADN. Traitement : varicocelectomie ou embolisation. Amélioration spermogramme dans 60-70% des cas.",tags:["Varicocèle","Température testiculaire","ROS","Spermatogenèse"]},
];

export const QB_BM_LCR = [
  {id:"bm_lcr1",prompt:"L'aspect normal du liquide céphalo-rachidien (LCR) est :",choices:["Trouble et jaunâtre","Clair, incolore, 'eau de roche'","Rosé avec quelques globules rouges","Légèrement opalescent"],answer:1,diff:1,explication:"LCR normal : limpide, incolore ('eau de roche'), < 5 cellules/mm³ (lymphocytes). Toute turbidité est pathologique. LCR trouble : méningite purulente. LCR xanthochromique (jaune) : hémorragie sous-arachnoïdienne ancienne (oxyhémoglobine → bilirubine). LCR hémorragique : HSA, traumatisme.",tags:["LCR","Aspect","Méningite","Xanthochromie"]},
  {id:"bm_lcr2",prompt:"Dans une méningite bactérienne, la glycorachie est typiquement :",choices:["Normale (> 0,45 g/L)","Abaissée (< 0,45 g/L), souvent < 0,2 g/L — rapport LCR/sang < 0,5","Élevée (> 1 g/L)","Nulle (0 g/L)"],answer:1,diff:2,explication:"Méningite bactérienne : métabolisme bactérien + leucocytes → consommation glucose → hypoglycorrachie (< 0,45 g/L, souvent < 0,2 g/L). Rapport glycorachie/glycémie < 0,5 (normal ≥ 0,5-0,6). Toujours doser la glycémie simultanément. Méningite virale : glycorachie normale.",tags:["Glycorachie","Méningite bactérienne","LCR","Biochimie"]},
  {id:"bm_lcr3",prompt:"La cytologie du LCR dans une méningite bactérienne purulente montre :",choices:["< 10 lymphocytes/mm³","Polynucléaires neutrophiles (PNN) prédominants, souvent > 1000/mm³","Lymphocytes et plasmocytes exclusivement","Hématies uniquement"],answer:1,diff:1,explication:"Méningite bactérienne : hypercytose à prédominance PNN (> 80%), souvent > 1000/mm³. Méningite virale : lymphocytose modérée (100-500/mm³). Méningite tuberculeuse : lymphocytes + quelques PNN + ↓ glycorachie + protéines > 1 g/L.",tags:["Cytologie LCR","PNN","Méningite bactérienne"]},
  {id:"bm_lcr4",prompt:"Dans la méningite à Listeria monocytogenes, le LCR est :",choices:["Toujours clair avec lymphocytose exclusive","Purulent dans 80% des cas, mixte dans 20% (PNN + lymphocytes)","Hémorragique par définition","Toujours normal biochimiquement"],answer:1,diff:2,explication:"Listeria : Gram positif, population à risque : immunodéprimés, âges extrêmes, femmes enceintes. LCR : purulent ~80%, mixte ~20% (atypique). IMPORTANT : résistance naturelle aux céphalosporines → ampicilline (+ gentamicine). Propriété psychrotrophe (croissance à 4°C).",tags:["Listeria","Méningite","LCR","Ampicilline","Céphalosporines"]},
  {id:"bm_lcr5",prompt:"Le test au latex (Pastorex Meningitis®) permet de détecter dans le LCR :",choices:["Tous les agents de méningite y compris viraux","Neisseria meningitidis (A/B/C/W/Y), S. pneumoniae, H. influenzae, Streptocoque B, E. coli K1","Uniquement Neisseria meningitidis","Uniquement les bactéries après culture positive"],answer:1,diff:2,explication:"Tests d'agglutination au latex : détection directe d'antigènes polysaccharidiques dans le LCR. Résultat en 15-30 min. Utile si antibiothérapie préalable. N. meningitidis B : sensibilité moindre. BinaxNOW® Pneumocoque : aussi testé sur urines.",tags:["Test au latex","Pastorex","Méningite","Diagnostic rapide"]},
  {id:"bm_lcr6",prompt:"La contre-indication principale à la ponction lombaire lors d'une suspicion de méningite est :",choices:["La fièvre élevée > 40°C","L'hypertension intracrânienne (HTIC) clinique ou radiologique — risque d'engagement cérébral","Une coagulopathie légère","Une infection cutanée à distance"],answer:1,diff:1,explication:"CI absolue : HTIC (risque d'engagement du tronc cérébral). Signes d'alerte : troubles de conscience, papillœdème, signes focaux. Dans ces cas : TDM cérébral AVANT la PL, mais antibiothérapie probabiliste EN URGENCE. Autres CI : troubles de coagulation sévères (TP < 50%, plaquettes < 50 G/L).",tags:["PL","HTIC","Contre-indication","Méningite"]},
  {id:"bm_lcr7",prompt:"La méningite tuberculeuse se distingue par un LCR :",choices:["Purulent à PNN avec hypoglycorrachie profonde","Lymphocytaire + protéinorachie > 1 g/L + hypoglycorrachie modérée + examen direct négatif (90%)","Clair avec protéines normales","Hémorragique"],answer:1,diff:2,explication:"Méningite tuberculeuse (MTB) : LCR clair/trouble, lymphocytaire (50-300/mm³), protéines élevées (1-4 g/L), hypoglycorrachie modérée. Direct Ziehl : positif dans 10-40% seulement. Culture Löwenstein : 2-8 sem. PCR MTB : Se ~60-80%. Traitement : RHZE × 2 mois puis RH × 7-10 mois.",tags:["Méningite tuberculeuse","LCR lymphocytaire","Ziehl-Neelsen","Hypoglycorrachie"]},
  {id:"bm_lcr8",prompt:"La protéinorachie normale dans le LCR est :",choices:["0 g/L","0,15 à 0,45 g/L (150 à 450 mg/L)","1 à 2 g/L","5 à 10 g/L"],answer:1,diff:1,explication:"Protéinorachie normale : 0,15-0,45 g/L. Hyperprotéinorachie dans : méningites (bactériennes > 1 g/L), tumeurs, HSA, Guillain-Barré (dissociation albuminocytologique : protéines ↑↑ + cytologie normale). Électrophorèse LCR : bandes oligoclonales dans la SEP.",tags:["Protéinorachie","LCR","Valeurs normales","Guillain-Barré"]},
  {id:"bm_lcr9",prompt:"La méningite virale à enterovirus se distingue de la méningite bactérienne par :",choices:["Un LCR purulent à PNN avec hypoglycorrachie","Un LCR clair, lymphocytaire modéré (100-500/mm³), protéinorachie < 1 g/L, glycorachie NORMALE","Un LCR xanthochromique","Un LCR acellulaire avec hyperprotéinorachie massive"],answer:1,diff:1,explication:"Méningite virale : LCR clair, lymphocytose modérée (100-500/mm³), protéines légèrement élevées (0,5-1 g/L), glycorachie NORMALE (crucial pour le diagnostic différentiel). Diagnostic : PCR enterovirus sur LCR. PCR HSV essentielle (traitement aciclovir urgent).",tags:["Méningite virale","Enterovirus","Glycorachie normale","PCR"]},
  {id:"bm_lcr10",prompt:"En cas de méningite suspectée avec signes d'HTIC (scanner non disponible rapidement), la conduite est :",choices:["Attendre le scanner avant toute action","Débuter immédiatement C3G IV + dexaméthasone SANS attendre la PL, puis PL après scanner","Réaliser la PL immédiatement sans scanner","Donner des antalgiques et attendre"],answer:1,diff:2,explication:"PROTOCOLE URGENCE : 1) Hémoc × 2 2) Antibiothérapie probabiliste EN URGENCE : ceftriaxone 2g IV + dexaméthasone 0,15 mg/kg SANS attendre la PL 3) TDM cérébral 4) PL si TDM normal. Si > 50 ans/immunodéprimé/grossesse : + ampicilline (Listeria).",tags:["Méningite","Urgence","HTIC","C3G","Antibiothérapie probabiliste"]},
];

export const QB_BM_COPRO = [
  {id:"bm_co1",prompt:"Le milieu de culture Hektoen est utilisé pour l'isolement de :",choices:["Staphylococcus aureus exclusivement","Les entérobactéries pathogènes intestinales (Salmonella, Shigella) — milieu sélectif et différentiel","Mycobactéries dans les selles","Virus intestinaux"],answer:1,diff:2,explication:"Hektoen (milieu sélectif chromogène) : inhibe la flore commensale (sels biliaires). Salmonella : colonies bleu-vert avec centre noir (H₂S). Shigella : verdâtres/bleues sans H₂S. Autres milieux : XLD, MLCB (Salmonella/Shigella). Milieu CIN : Yersinia. Campylosel/CCDA : Campylobacter.",tags:["Hektoen","Coproculture","Salmonella","Shigella"]},
  {id:"bm_co2",prompt:"La culture de Campylobacter jejuni nécessite :",choices:["Conditions anaérobies strictes à 25°C","Microaérophilie (5% O2, 10% CO2) et incubation à 42°C sur milieu sélectif (Campylosel ou CCDA)","Conditions aérobies à 37°C sur gélose ordinaire","Conditions anaérobies à 37°C"],answer:1,diff:2,explication:"Campylobacter jejuni : Gram négatif incurvé. Microaérophilie stricte (5-10% O2), 42°C (optimal, inhibe flore fécale), milieux sélectifs (Campylosel, CCDA). Identification : oxydase+, hippurate+. Complication grave : syndrome de Guillain-Barré (10-15j après infection).",tags:["Campylobacter","Microaérophilie","42°C","Guillain-Barré"]},
  {id:"bm_co3",prompt:"La PCR multiplex sur selles permet de :",choices:["Permettre l'antibiogramme directement","Détecter simultanément de nombreux agents (bactéries, virus, parasites) en 1-2h avec haute sensibilité","Être moins coûteuse que la culture classique","Ne détecter que les bactéries pathogènes"],answer:1,diff:2,explication:"PCR multiplex (FilmArray® GI Panel) : détecte en ~1-2h jusqu'à 22 cibles (Salmonella, Campylobacter, EHEC, C. difficile, norovirus, rotavirus, Giardia, Cryptosporidium, etc.). Inconvénients : pas d'antibiogramme, coût élevé, risque de surdiagnostic (portage). Culture nécessaire pour antibiogramme.",tags:["PCR multiplex","Coproculture","FilmArray","Diagnostic rapide"]},
  {id:"bm_co4",prompt:"Le syndrome hémolytique et urémique (SHU) de l'enfant est classiquement associé à :",choices:["Salmonella typhi","E. coli entérohémorragique (EHEC) producteurs de shigatoxines — sérotype O157:H7","Rotavirus","Shigella sonnei"],answer:1,diff:1,explication:"EHEC (E. coli entérohémorragique) : shigatoxines Stx1/Stx2 → SHU (IRA + MAHA + thrombopénie). Principal sérotype : O157:H7. Contre-indication ABSOLUE aux antibiotiques (lyse bactérienne → libération Stx → ↑ risque SHU). Déclaration obligatoire. Diagnostic : PCR Stx + culture sur milieu sorbitol Mac Conkey.",tags:["EHEC","SHU","Shigatoxines","O157:H7","Antibiotiques CI"]},
  {id:"bm_co5",prompt:"L'algorithme diagnostique de C. difficile repose en 1ère intention sur :",choices:["L'hémoculture","Recherche GDH + toxines A/B par immunochromatographie (+ confirmation PCR si discordance)","La coloration de Gram des selles","La coproculture aérobie sur Hektoen"],answer:1,diff:2,explication:"Algorithme C. difficile (HAS) : 1) GDH (antigène commun, haute VPN) + toxines A/B (immunochromatographie rapide). Discordance GDH+/toxines- → PCR. Cause principale de diarrhée nosocomiale. Facteur de risque : ATB large spectre (C3G, FQ). Traitement 1e ligne : métronidazole (formes légères) ou vancomycine orale (formes sévères).",tags:["C. difficile","GDH","Toxines","PCR","Diarrhée nosocomiale"]},
  {id:"bm_co6",prompt:"L'examen parasitologique des selles pour Giardia lamblia nécessite :",choices:["Un seul prélèvement","3 prélèvements à 3-5 jours d'intervalle (émission de kystes intermittente) + conservation au SAF","Un prélèvement de sang simultané","Un prélèvement sous coelioscopie"],answer:1,diff:2,explication:"EPS pour Giardia : 3 prélèvements à 3-5j d'intervalle (excrétion de kystes intermittente → risque faux négatifs sur 1 seul prélèvement). Conservation SAF. Technique : Lugol (kystes 10-14 µm, 4 noyaux). Également : Ag fécaux ELISA (haute sensibilité). Traitement : métronidazole.",tags:["Giardia","EPS","Kystes","SAF","3 prélèvements"]},
  {id:"bm_co7",prompt:"La mise en évidence de Cryptosporidium dans les selles se fait par :",choices:["Coloration de Gram classique","Ziehl-Neelsen modifié à froid ou immunofluorescence — oocystes résistants à la chloration","Hémoculture","Culture sur milieu Hektoen"],answer:1,diff:2,explication:"Cryptosporidium : protozoaire, oocystes 4-6 µm. Ziehl-Neelsen à froid (oocystes rose-rouge sur fond vert). IFD : méthode de référence. Résistant à la chloration → épidémies hydriques. Population à risque : immunodéprimés (VIH). Diagnostic également par panneaux PCR multiplex.",tags:["Cryptosporidium","Ziehl-Neelsen","Oocystes","VIH"]},
  {id:"bm_co8",prompt:"Les oeufs de Taenia solium et T. saginata dans les selles sont :",choices:["Facilement distinguables par morphologie","Morphologiquement identiques (différenciation uniquement par les crochets du scolex ou structure des proglottis gravides)","Uniquement détectables par PCR","Toujours présents en grande quantité"],answer:1,diff:3,explication:"Oeufs de Taenia : sphériques, paroi striée, 30-40 µm, oncosphère à 6 crochets — identiques pour les 2 espèces. Différenciation : proglottis gravides (T. saginata > 13 ramifications; T. solium < 13) ou crochets sur scolex (T. solium = taenia armé uniquement). T. solium seul responsable de la cysticercose (larves cérébrales).",tags:["Taenia","Oeufs","T. solium","Cysticercose","Parasitologie"]},
  {id:"bm_co9",prompt:"Yersinia enterocolitica nécessite pour son isolement :",choices:["42°C en microaérophilie","Enrichissement à 4°C (psychrotrophie) + milieu sélectif CIN à 32-37°C","48°C en anaérobiose","37°C sur Hektoen"],answer:1,diff:3,explication:"Yersinia enterocolitica : psychrotrophe (se multiplie à 4°C). Enrichissement à froid (PBS à 4°C, 3-4 semaines). Milieu CIN (colonies 'oeil de boeuf' rose-bordeaux). Identification : uréase+, VP+ à 25°C. Complications : arthrite réactive, érythème noueux, thyroïdite.",tags:["Yersinia","Psychrotrophie","Milieu CIN","Enrichissement à froid"]},
  {id:"bm_co10",prompt:"Dans la fièvre typhoïde, quel prélèvement est le plus rentable en 1ère semaine ?",choices:["Coproculture uniquement","Hémocultures (rentabilité 80-90%) — bactériémie à Salmonella Typhi","Sérodiagnostic Widal uniquement","Ponction médullaire uniquement"],answer:1,diff:2,explication:"Fièvre typhoïde : Salmonella Typhi. Phase bactériémique (1ère semaine) : hémocultures ++ (80-90% de positivité). 2e semaine : myéloculture (plus sensible), coproculture positive. Sérodiagnostic Widal-Félix : 3e semaine, peu spécifique. Maladie à déclaration obligatoire (DO). Traitement : fluoroquinolones ou azithromycine.",tags:["Fièvre typhoïde","Salmonella Typhi","Hémoculture","Widal"]},
];

export const QB_BM_ACIDES_NUCL = [
  {id:"bm_an1",prompt:"Un nucléotide est composé de :",choices:["Uniquement d'une base azotée et d'un sucre","D'une base azotée + d'un pentose + d'un ou plusieurs groupements phosphate","D'une base azotée uniquement","D'un acide aminé + un sucre + un phosphate"],answer:1,diff:1,explication:"Nucléotide = base azotée + pentose + 1-3 groupements phosphate. Nucléoside = base + pentose (sans phosphate). Bases puriques (2 cycles) : A, G. Bases pyrimidiques (1 cycle) : C, T (ADN), U (ARN). ADN : désoxyribose. ARN : ribose.",tags:["Nucléotide","Nucléoside","Base azotée","Pentose","Phosphate"]},
  {id:"bm_an2",prompt:"La règle de Chargaff stipule que dans l'ADN double brin :",choices:["[A] = [G] et [C] = [T]","[A] = [T] et [G] = [C] (complémentarité des bases Watson-Crick)","[A] + [T] = [G] + [C]","[A] > [T] dans les organismes à GC% élevé"],answer:1,diff:1,explication:"Règle de Chargaff (1950) : [A] = [T] et [G] = [C] dans l'ADN double brin. Cette règle a guidé Watson et Crick vers la double hélice (1953). Appariement antiparallèle : A-T (2 liaisons hydrogène), G-C (3 liaisons hydrogène → paires G-C plus stables thermiquement).",tags:["Chargaff","ADN","Appariement","Liaisons hydrogène"]},
  {id:"bm_an3",prompt:"Les liaisons hydrogène entre les paires de bases de l'ADN sont :",choices:["A-T = 3 liaisons H et G-C = 2 liaisons H","A-T = 2 liaisons H et G-C = 3 liaisons H (paire G-C plus stable)","A-T = 1 liaison H et G-C = 2 liaisons H","A-T et G-C ont le même nombre (2)"],answer:1,diff:2,explication:"Appariement Watson-Crick : A—T : 2 liaisons H (moins stables). G≡C : 3 liaisons H (plus stables). Plus le %GC est élevé, plus la Tm est haute. Application PCR : température d'hybridation des amorces dépend de leur Tm. Règle simplifiée : Tm ≈ 4(G+C) + 2(A+T) pour oligonucléotides courts.",tags:["Liaisons hydrogène","A-T","G-C","Tm","Stabilité"]},
  {id:"bm_an4",prompt:"Le nucléosome, unité de base de la chromatine, est constitué de :",choices:["Un brin d'ADN enroulé autour de 4 histones H1","146 paires de bases d'ADN enroulées autour d'un octamère d'histones (2×H2A, 2×H2B, 2×H3, 2×H4)","Un brin d'ADN + une protéine non histone","200 pb d'ADN + 8 histones dont H1"],answer:1,diff:2,explication:"Nucléosome : 146 pb d'ADN (1,65 tour) + octamère d'histones (2×H2A, 2×H2B, 2×H3, 2×H4). H1 : histone de liaison (ADN linker, ~20-80 pb entre nucléosomes). Modifications histones (acétylation, méthylation) → régulation de l'expression génique (épigénétique).",tags:["Nucléosome","Histones","Chromatine","146 pb","Épigénétique"]},
  {id:"bm_an5",prompt:"La température de fusion (Tm) d'un ADN double brin représente :",choices:["La température d'élongation en PCR","La température à laquelle 50% des doubles hélices sont dénaturées (séparation des 2 brins)","La température optimale de l'ADN polymérase","La température de synthèse maximale d'ADN"],answer:1,diff:2,explication:"Tm = température à laquelle 50% de l'ADN est dénaturé. Mesurée par suivi de l'absorbance à 260 nm (hyperchromicité : l'ADN dénaturé absorbe plus). Tm ≈ 86°C pour ADN génomique à 50% GC. En PCR : température d'hybridation ~ Tm - 5°C.",tags:["Tm","Dénaturation","260 nm","GC%","PCR"]},
  {id:"bm_an6",prompt:"L'absorbance maximale des acides nucléiques dans l'UV est à :",choices:["214 nm","260 nm (cycles aromatiques des bases — A260/A280 ≥ 1,8 pour ADN pur)","280 nm","340 nm"],answer:1,diff:1,explication:"Acides nucléiques : absorption max à 260 nm (bases aromatiques). Ratio A260/A280 : ADN pur = 1,8-2,0. ARN pur ~ 2,0. Ratio < 1,8 → contamination protéique. Protéines absorbent à 280 nm (Trp, Tyr). 1 unité A260 ≈ 50 µg/mL d'ADN double brin.",tags:["260 nm","Spectrophotométrie","A260/A280","Pureté ADN"]},
  {id:"bm_an7",prompt:"L'hydrolyse alcaline dégrade spécifiquement :",choices:["L'ADN uniquement","L'ARN uniquement (le groupement 2'-OH du ribose permet une attaque nucléophile intramoléculaire)","Les deux de façon identique","Aucun des deux"],answer:1,diff:3,explication:"Hydrolyse alcaline sélective de l'ARN : le groupement 2'-OH du ribose (absent dans l'ADN) effectue une attaque nucléophile sur le phosphore → formation intermédiaire 2',3'-cyclo-phosphate → hydrolyse. L'ADN (désoxyribose, pas de 2'-OH) est stable en milieu alcalin. Application : purification de plasmides (lyse alcaline).",tags:["Hydrolyse alcaline","ARN","2'-OH","Ribose","Sélectivité"]},
  {id:"bm_an8",prompt:"La transcription inverse (rétrotranscription) consiste en :",choices:["La synthèse d'ADN à partir d'un ADN matrice","La synthèse d'ADN complémentaire (ADNc) à partir d'un ARNm, catalysée par la transcriptase inverse","La synthèse d'ARN à partir d'ADN","La traduction de l'ARNm en protéine"],answer:1,diff:1,explication:"Transcriptase inverse (RT) : enzyme clé des rétrovirus (VIH). Copie ARN → ADNc. Applications : RT-PCR (expression génique) ; quantification charge virale VIH. L'ADNc ne contient pas d'introns (seulement exons). Inhibiteurs RT = antirétroviraux : INTI (AZT) et INNTI (efavirenz).",tags:["Transcriptase inverse","ADNc","RT-PCR","VIH","Rétrovirus"]},
  {id:"bm_an9",prompt:"La PCR en temps réel (qPCR) utilise comme indicateur de quantification :",choices:["Le nombre de bandes sur gel d'agarose","La fluorescence cycle par cycle (Ct inversement proportionnel à la quantité initiale)","La taille des fragments amplifiés","La couleur du produit d'amplification"],answer:1,diff:2,explication:"qPCR : mesure fluorescence (SYBR Green ou sonde TaqMan) à chaque cycle. Ct = cycle où fluorescence dépasse un seuil : plus Ct bas, plus grande la quantité initiale. Courbe standard → quantification absolue. Applications : charge virale VIH/VHB/VHC, MRD en hématologie, Aspergillus.",tags:["qPCR","Ct","Fluorescence","Quantification","Charge virale"]},
  {id:"bm_an10",prompt:"Le Southern blot permet de :",choices:["Détecter des protéines spécifiques","Détecter des fragments d'ADN spécifiques après digestion par enzymes de restriction, migration sur gel, transfert sur membrane et hybridation avec sonde","Détecter des ARNm (Northern blot)","Identifier des anticorps (Western blot)"],answer:1,diff:2,explication:"Southern blot (E. Southern, 1975) : 1) Digestion ADN (enzyme de restriction) 2) Électrophorèse gel agarose 3) Dénaturation + transfert membrane nylon 4) Hybridation sonde marquée 5) Révélation. Applications : réarrangements géniques (lymphomes, leucémies). Northern = ARN. Western = protéines.",tags:["Southern blot","ADN","Enzyme de restriction","Hybridation"]},
];

